import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ServicePackage {
  hours: number;
  sessions: number;
  books: number;
}

export interface PricingConstants {
  HOUR_PRICE: number;
  SESSION_PRICE: number;
  BOOK_PRICE: number;
  MIN_BUDGET: number;
  STEP: number;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { PricingConstants } from './types';

export const PRICING: PricingConstants = {
  HOUR_PRICE: 25,
  SESSION_PRICE: 100,
  BOOK_PRICE: 200,
  MIN_BUDGET: 50,
  STEP: 25,
};

export const PORTFOLIO_IMAGES = [
  'https://images.unsplash.com/photo-1519741497674-611481863552?auto=format&fit=crop&q=80&w=800',
  'https://images.unsplash.com/photo-1511285560929-80b456fea0bc?auto=format&fit=crop&q=80&w=800',
  'https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?auto=format&fit=crop&q=80&w=800',
  'https://images.unsplash.com/photo-1537633552985-df8429e8048b?auto=format&fit=crop&q=80&w=800',
  'https://images.unsplash.com/photo-1470217957101-da7150b9b681?auto=format&fit=crop&q=80&w=800',
  'https://images.unsplash.com/photo-1520852758249-f47262176377?auto=format&fit=crop&q=80&w=800'
];

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getPhotographyConsultation = async (prompt: string, budget: number) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional photography consultant for 'Lumina Frames'. 
      A client is interested in our services. 
      Our pricing: $25/hour, $100/session, $200/photo-book.
      The client's current selected budget is $${budget}.

      User request: "${prompt}"

      Provide a creative and helpful response. Suggest how they can best spend their $${budget} budget based on their request. 
      Be encouraging, professional, and concise. Keep formatting clean with bullet points if needed.`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm sorry, I'm having a bit of trouble connecting to our creative database. Please feel free to reach out to us directly!";
  }
};

import React from 'react';
import { PRICING } from '../constants';

interface PriceSliderProps {
  value: number;
  onChange: (val: number) => void;
}

const PriceSlider: React.FC<PriceSliderProps> = ({ value, onChange }) => {
  return (
    <div className="w-full max-w-2xl mx-auto space-y-6">
      <div className="flex justify-between items-end mb-2">
        <div>
          <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider">Your Investment</h3>
          <p className="text-4xl font-serif font-bold text-primary">
            ${value}
          </p>
        </div>
        <div className="text-right">
          <p className="text-xs text-gray-400">Incremental adjustments of ${PRICING.STEP}</p>
        </div>
      </div>

      <input
        type="range"
        min={PRICING.MIN_BUDGET}
