export default PriceSlider;

import React from 'react';
import { PRICING } from '../constants';

interface BudgetAllocationProps {
  budget: number;
}

const BudgetAllocation: React.FC<BudgetAllocationProps> = ({ budget }) => {
  // Logic to show a possible combination
  const maxBooks = Math.floor(budget / PRICING.BOOK_PRICE);
  const remainingAfterBooks = budget % PRICING.BOOK_PRICE;

  const maxSessions = Math.floor(remainingAfterBooks / PRICING.SESSION_PRICE);
  const remainingAfterSessions = remainingAfterBooks % PRICING.SESSION_PRICE;

  const maxHours = Math.floor(remainingAfterSessions / PRICING.HOUR_PRICE);

  const items = [
    { name: 'Photo-Books', count: maxBooks, price: PRICING.BOOK_PRICE, color: 'bg-indigo-600', icon: '📚' },
    { name: 'Photo-Sessions', count: maxSessions, price: PRICING.SESSION_PRICE, color: 'bg-emerald-600', icon: '📸' },
    { name: 'Photography Hours', count: maxHours, price: PRICING.HOUR_PRICE, color: 'bg-amber-500', icon: '⏱️' },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-12">
      {items.map((item) => (
        <div key={item.name} className="relative group overflow-hidden bg-white p-6 rounded-2xl shadow-sm border border-gray-100 transition-all hover:shadow-md">
          <div className={`absolute top-0 right-0 w-24 h-24 -mr-8 -mt-8 rounded-full opacity-10 ${item.color}`}></div>
          <div className="text-3xl mb-4">{item.icon}</div>
          <h4 className="text-lg font-bold text-gray-800">{item.name}</h4>
          <p className="text-sm text-gray-500 mb-4">${item.price} per unit</p>
          <div className="flex items-center space-x-2">
            <span className="text-3xl font-serif font-bold text-primary">{item.count}</span>
            <span className="text-sm text-gray-400">Included</span>
          </div>
        </div>
      ))}
    </div>
  );
};

export default BudgetAllocation;

import React, { useState, useRef, useEffect } from 'react';
import { getPhotographyConsultation } from '../services/geminiService';
import { Message } from '../types';

interface ChatAssistantProps {
  budget: number;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ budget }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: `Hi! I'm your Lumina AI Consultant. I see you're looking at a $${budget} budget. What kind of memories are we capturing? (e.g., Wedding, Corporate, or a Personal Portrait session?)` }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    const aiResponse = await getPhotographyConsultation(userMsg, budget);

    setMessages(prev => [...prev, { role: 'model', text: aiResponse }]);
    setLoading(false);
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden flex flex-col h-[500px]">
      <div className="bg-primary p-4 text-white flex items-center space-x-3">
        <div className="w-8 h-8 rounded-full bg-accent flex items-center justify-center text-xs font-bold">AI</div>
        <div>
          <h3 className="font-medium text-sm">Session Consultant</h3>
          <p className="text-[10px] text-gray-300">Powered by Gemini</p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
              m.role === 'user' 
                ? 'bg-accent text-white rounded-tr-none' 
                : 'bg-gray-100 text-gray-800 rounded-tl-none'
            }`}>
              {m.text.split('\n').map((line, j) => (
                <p key={j} className={line.startsWith('*') || line.startsWith('-') ? 'ml-4' : 'mb-2'}>
                  {line}
                </p>
              ))}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-gray-100 p-3 rounded-2xl animate-pulse text-gray-400 text-xs">Thinking...</div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 flex space-x-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Ask about your shoot idea..."
          className="flex-1 bg-gray-50 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-accent/50"
        />
        <button
          onClick={handleSend}
          disabled={loading}
          className="bg-primary text-white p-2 rounded-full hover:bg-gray-800 transition-colors disabled:opacity-50"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
          </svg>
        </button>
      </div>
    </div>
  );
};

export default ChatAssistant;

export interface Selection {
  hours: number;
  sessions: number;
  books: number;
  booksEnabled: boolean;
  sessionsEnabled: boolean;
  hoursEnabled: boolean;
}

export interface PricingConstants {
  HOUR_PRICE: number;
  SESSION_PRICE: number;
  BOOK_PRICE: number;
  MIN_BUDGET: number;
  STEP: number;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import React from 'react';
import { PRICING } from '../constants';
import { Selection } from '../types';

interface BudgetAllocationProps {
  selection: Selection;
  onUpdate: (update: Partial<Selection>) => void;
  maxBudget: number;
}

const BudgetAllocation: React.FC<BudgetAllocationProps> = ({ selection, onUpdate, maxBudget }) => {
  const totalCost = 
    (selection.hoursEnabled ? selection.hours * PRICING.HOUR_PRICE : 0) +
    (selection.sessionsEnabled ? selection.sessions * PRICING.SESSION_PRICE : 0) +
    (selection.booksEnabled ? selection.books * PRICING.BOOK_PRICE : 0);

  const isOverBudget = totalCost > maxBudget;

  const items = [
    { 
      id: 'books',
      name: 'Photo-Books', 
      count: selection.books, 
      enabled: selection.booksEnabled,
      price: PRICING.BOOK_PRICE, 
      color: 'bg-indigo-600', 
      icon: '📚' 
    },
    { 
      id: 'sessions',
      name: 'Photo-Sessions', 
      count: selection.sessions, 
      enabled: selection.sessionsEnabled,
      price: PRICING.SESSION_PRICE, 
      color: 'bg-emerald-600', 
      icon: '📸' 
    },
    { 
      id: 'hours',
      name: 'Photography Hours', 
      count: selection.hours, 
      enabled: selection.hoursEnabled,
      price: PRICING.HOUR_PRICE, 
      color: 'bg-amber-500', 
      icon: '⏱️' 
    },
  ];

  const handleToggle = (id: string, enabled: boolean) => {
    const update: any = { [`${id}Enabled`]: !enabled };
    // If enabling and count is 0, set to 1
    if (!enabled && selection[id as keyof Selection] === 0) {
      update[id] = 1;
    }
    onUpdate(update);
  };

  const handleAdjust = (id: string, delta: number) => {
    const currentVal = selection[id as keyof Selection] as number;
    const newVal = Math.max(0, currentVal + delta);
    const update: any = { [id]: newVal };
    // Auto-enable if increasing above 0
    if (newVal > 0) {
      update[`${id}Enabled`] = true;
    } else {
      update[`${id}Enabled`] = false;
    }
    onUpdate(update);
  };

  return (
    <div className="space-y-8 mt-12">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {items.map((item) => (
          <div 
            key={item.id} 
            className={`relative group overflow-hidden bg-white p-6 rounded-2xl shadow-sm border transition-all hover:shadow-md ${
              item.enabled ? 'border-accent ring-1 ring-accent/20' : 'border-gray-100 opacity-60'
            }`}
          >
            <div className="flex justify-between items-start mb-4">
              <div className="text-3xl">{item.icon}</div>
              <input 
                type="checkbox" 
                checked={item.enabled}
                onChange={() => handleToggle(item.id, item.enabled)}
                className="w-5 h-5 accent-accent cursor-pointer rounded border-gray-300 focus:ring-accent"
              />
            </div>

            <h4 className="text-lg font-bold text-gray-800">{item.name}</h4>
            <p className="text-xs text-gray-500 mb-6">${item.price} per unit</p>

            <div className="flex items-center justify-between bg-gray-50 rounded-xl p-2">
              <button 
                onClick={() => handleAdjust(item.id, -1)}
                className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors"
                aria-label="Decrease"
              >
                -
              </button>
              <span className="text-2xl font-serif font-bold text-primary px-4">
                {item.count}
              </span>
              <button 
                onClick={() => handleAdjust(item.id, 1)}
                className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors"
                aria-label="Increase"
              >
                +
              </button>
            </div>
          </div>
        ))}
      </div>

      <div className={`p-6 rounded-2xl border transition-all ${
        isOverBudget ? 'bg-red-50 border-red-200' : 'bg-accent/5 border-accent/20'
      }`}>
        <div className="flex justify-between items-center">
          <div>
            <p className="text-xs uppercase tracking-widest text-gray-500 font-bold mb-1">Total Estimated Cost</p>
            <p className={`text-3xl font-serif font-bold ${isOverBudget ? 'text-red-600' : 'text-primary'}`}>
              ${totalCost}
            </p>
          </div>
          <div className="text-right">
            <p className="text-xs text-gray-500">Remaining Budget</p>
            <p className={`text-xl font-bold ${isOverBudget ? 'text-red-500' : 'text-emerald-600'}`}>
              {isOverBudget ? `-$${totalCost - maxBudget}` : `$${maxBudget - totalCost}`}
            </p>
          </div>
        </div>
        {isOverBudget && (
          <p className="text-[10px] text-red-500 mt-2 font-medium">⚠️ Selection exceeds your target budget of ${maxBudget}. Adjust your items or increase the budget slider.</p>
        )}
      </div>
    </div>
  );
};

export default BudgetAllocation;

