  onUpdate: (update: Partial<Selection>) => void;
  maxBudget: number;
}

const BudgetAllocation: React.FC<BudgetAllocationProps> = ({ selection, onUpdate, maxBudget }) => {
  const totalCost = 
    (selection.hoursEnabled ? selection.hours * PRICING.HOUR_PRICE : 0) +
    (selection.sessionsEnabled ? selection.sessions * PRICING.SESSION_PRICE : 0) +
    (selection.booksEnabled ? selection.books * PRICING.BOOK_PRICE : 0);

  const isOverBudget = totalCost > maxBudget;

  const items = [
    { 
      id: 'hours',
      name: 'Photography Hours', 
      count: selection.hours, 
      enabled: selection.hoursEnabled,
      price: PRICING.HOUR_PRICE, 
      unitLabel: 'per hour',
      color: 'bg-amber-500', 
      icon: '⏱️',
      min: 1
    },
    { 
      id: 'sessions',
      name: 'Photo-Sessions', 
      count: selection.sessions, 
      enabled: selection.sessionsEnabled,
      price: PRICING.SESSION_PRICE, 
      unitLabel: 'per session',
      color: 'bg-emerald-600', 
      icon: '📸',
      min: 0
    },
    { 
      id: 'books',
      name: 'Photo-Books', 
      count: selection.books, 
      enabled: selection.booksEnabled,
      price: PRICING.BOOK_PRICE, 
      unitLabel: 'per photo-book 30x20cm',
      color: 'bg-indigo-600', 
      icon: '📚',
      min: 0
    },
  ];

  const handleToggle = (id: string, enabled: boolean) => {
    const update: any = { [`${id}Enabled`]: !enabled };

    // If enabling and count is below minimum, set to minimum
    const itemConfig = items.find(item => item.id === id);
    const minVal = itemConfig?.min ?? 0;

    if (!enabled && selection[id as keyof Selection] < minVal) {
      update[id] = minVal;
    }
    onUpdate(update);
  };

  const handleAdjust = (id: string, delta: number) => {
    const currentVal = selection[id as keyof Selection] as number;
    const itemConfig = items.find(item => item.id === id);
    const minVal = itemConfig?.min ?? 0;

    const newVal = Math.max(minVal, currentVal + delta);
    const update: any = { [id]: newVal };

    // Auto-enable if it's hours (since min is 1) or if increasing above 0
    if (newVal > 0) {
      update[`${id}Enabled`] = true;
    } else {
      update[`${id}Enabled`] = false;
    }
    onUpdate(update);
  };

  return (
    <div className="space-y-8 mt-12">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {items.map((item) => (
          <div 
            key={item.id} 
            className={`relative group overflow-hidden bg-white p-6 rounded-2xl shadow-sm border transition-all hover:shadow-md ${
              item.enabled ? 'border-accent ring-1 ring-accent/20' : 'border-gray-100 opacity-60'
            }`}
          >
            <div className="flex justify-between items-start mb-4">
              <div className="text-3xl">{item.icon}</div>
              <input 
                type="checkbox" 
                checked={item.enabled}
                onChange={() => handleToggle(item.id, item.enabled)}
                className="w-5 h-5 accent-accent cursor-pointer rounded border-gray-300 focus:ring-accent"
              />
            </div>

            <h4 className="text-lg font-bold text-gray-800">{item.name}</h4>
            <p className="text-xs text-gray-500 mb-6">${item.price} {item.unitLabel}</p>

            <div className="flex items-center justify-between bg-gray-50 rounded-xl p-2">
              <button 
                onClick={() => handleAdjust(item.id, -1)}
                className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors"
                aria-label="Decrease"
              >
                -
              </button>
              <span className="text-2xl font-serif font-bold text-primary px-4">
                {item.count}
              </span>
              <button 
                onClick={() => handleAdjust(item.id, 1)}
                className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors"
                aria-label="Increase"
              >
                +
              </button>
            </div>
            {item.id === 'hours' && (
              <p className="text-[10px] text-gray-400 mt-2 italic">* Minimum 1 hour required</p>
            )}
          </div>
        ))}
      </div>

      <div className={`p-6 rounded-2xl border transition-all ${
        isOverBudget ? 'bg-red-50 border-red-200' : 'bg-accent/5 border-accent/20'
      }`}>
        <div className="flex justify-between items-center">
          <div>
            <p className="text-xs uppercase tracking-widest text-gray-500 font-bold mb-1">Total Estimated Cost</p>
            <p className={`text-3xl font-serif font-bold ${isOverBudget ? 'text-red-600' : 'text-primary'}`}>
              ${totalCost}
            </p>
          </div>
          <div className="text-right">
            <p className="text-xs text-gray-500">Target Budget</p>
            <p className={`text-xl font-bold ${isOverBudget ? 'text-red-500' : 'text-emerald-600'}`}>
              ${maxBudget}
            </p>
          </div>
        </div>
        {isOverBudget && (
          <p className="text-[10px] text-red-500 mt-2 font-medium">⚠️ Selection exceeds your target budget. Adjust your items or increase the budget slider.</p>
        )}
      </div>
    </div>
  );
};

export default BudgetAllocation;

