import { GoogleGenAI } from "@google/genai";

// Always use named parameter for apiKey and use process.env.API_KEY directly
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getPhotographyConsultation = async (prompt: string, budget: number) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional photography consultant for 'Lumina Frames'. 
      A client is interested in our services. 
      Our pricing: $25/hour, $100/session, $200/photo-book.
      The client's current selected budget is $${budget}.

      User request: "${prompt}"

      Provide a creative and helpful response. Suggest how they can best spend their $${budget} budget based on their request. 
      Be encouraging, professional, and concise. Keep formatting clean with bullet points if needed.`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });
    // The text content is obtained by accessing the .text property directly
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm sorry, I'm having a bit of trouble connecting to our creative database. Please feel free to reach out to us directly!";
  }
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import PriceSlider from './components/PriceSlider';
import BudgetAllocation from './components/BudgetAllocation';
import ChatAssistant from './components/ChatAssistant';
import { PORTFOLIO_IMAGES, PRICING } from './constants';
import { Selection } from './types';

const App: React.FC = () => {
  // Initial state matches $50 requirement (2 hours @ $25 each)
  const [maxBudget, setMaxBudget] = useState(50);
  const [selection, setSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    booksEnabled: true, // Always enabled now that checkboxes are removed
    sessionsEnabled: true,
    hoursEnabled: true,
  });

  const calculateTotal = useCallback((sel: Selection) => {
    return (
      (sel.hoursEnabled ? sel.hours * PRICING.HOUR_PRICE : 0) +
      (sel.sessionsEnabled ? sel.sessions * PRICING.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * PRICING.BOOK_PRICE : 0)
    );
  }, []);

  // The slider should never go below the cost of fixed items + 2 hours
  const minBudgetAllowed = useMemo(() => {
    const fixedCosts = 
      (selection.sessionsEnabled ? selection.sessions * PRICING.SESSION_PRICE : 0) +
      (selection.booksEnabled ? selection.books * PRICING.BOOK_PRICE : 0);
    // Photography hours minimum value is now 2 ($50)
    return fixedCosts + (2 * PRICING.HOUR_PRICE);
  }, [selection.sessions, selection.sessionsEnabled, selection.books, selection.booksEnabled]);

  const handleUpdateSelection = (update: Partial<Selection>) => {
    setSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next);
      // Synchronize slider with selection changes.
      setMaxBudget(Math.max(minBudgetAllowed, newTotal));
      return next;
    });
  };

  const handleSliderChange = (newVal: number) => {
    // Constraint: don't let the slider go left under total estimated cost (fixed + 2hr min)
    const effectiveVal = Math.max(minBudgetAllowed, newVal);
    setMaxBudget(effectiveVal);

    // When slider is moving, only photography hours is changing
    setSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * PRICING.BOOK_PRICE : 0);

      const remainingBudget = effectiveVal - fixedCosts;
      // Photography hours minimum value is 2
      const newHours = Math.max(2, Math.floor(remainingBudget / PRICING.HOUR_PRICE));

      return {
        ...prev,
        hours: newHours,
        hoursEnabled: true
      };
    });
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Navbar */}
      <nav className="fixed top-0 w-full z-50 glass-morphism border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <span className="text-white font-serif font-bold italic">L</span>
            </div>
            <span className="font-serif text-xl font-bold tracking-tight">LUMINA FRAMES</span>
          </div>
          <div className="hidden md:flex space-x-8 text-sm font-medium text-gray-600">
            <a href="#" className="hover:text-accent transition-colors">Portfolio</a>
            <a href="#" className="hover:text-accent transition-colors">Pricing</a>
            <a href="#" className="hover:text-accent transition-colors">Our Studio</a>
            <button className="bg-primary text-white px-6 py-2 rounded-full text-xs uppercase tracking-widest hover:bg-accent transition-all">Book Now</button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <header className="pt-32 pb-20 px-6 bg-[#fafafa]">
        <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-12 items-center">
          <div className="space-y-8">
            <h1 className="text-6xl md:text-7xl font-serif font-bold leading-tight">
              Capturing <br />
              <span className="text-accent italic">Timeless</span> <br />
              Moments.
            </h1>
            <p className="text-lg text-gray-500 max-w-md leading-relaxed">
              Professional photography services tailored to your budget. From personal portraits to grand celebrations, we frame your story with elegance.
            </p>
            <div className="flex space-x-4">
              <a href="#planner" className="bg-primary text-white px-8 py-4 rounded-full font-medium hover:bg-gray-800 transition-all shadow-lg">Plan Your Session</a>
              <a href="#portfolio" className="border border-gray-300 px-8 py-4 rounded-full font-medium hover:bg-gray-50 transition-all">View Work</a>
            </div>
          </div>
          <div className="relative">
            <div className="aspect-[4/5] rounded-3xl overflow-hidden shadow-2xl">
              <img 
                src="https://images.unsplash.com/photo-1554080353-a576cf803bda?auto=format&fit=crop&q=80&w=1200" 
                alt="Professional camera" 
                className="w-full h-full object-cover"
              />
            </div>
            <div className="absolute -bottom-6 -left-6 glass-morphism p-6 rounded-2xl shadow-xl hidden md:block">
              <div className="flex items-center space-x-4">
                <div className="flex -space-x-2">
                  {[1, 2, 3].map(i => (
                    <img key={i} src={`https://picsum.photos/seed/${i}/40/40`} className="w-10 h-10 rounded-full border-2 border-white" />
                  ))}
                </div>
                <div>
                  <p className="text-xs font-bold">500+ Happy Clients</p>
                  <p className="text-[10px] text-gray-500">Across 12 Countries</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Pricing Planner */}
      <section id="planner" className="py-24 px-6 bg-white">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-16">
            <h2 className="text-3xl font-serif font-bold mb-2">Build Your Package</h2>
            <p className="text-gray-500">Adjust the range below to see how many photography hours fit your desired investment.</p>
          </div>

          <div className="grid lg:grid-cols-3 gap-12 items-start">
            <div className="lg:col-span-2 bg-gray-50/50 p-8 md:p-12 rounded-[2rem] border border-gray-100">
              <div className="mb-12">
                <div className="flex flex-col items-center mb-8">
