                <p className="text-sm text-gray-600 mb-6 leading-relaxed">
                  Discuss how to optimize your ${maxBudget} investment for your specific photography needs.
                </p>
                <ChatAssistant budget={maxBudget} />
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Portfolio Grid */}
      <section id="portfolio" className="py-24 px-6 bg-[#fafafa]">
        <div className="max-w-7xl mx-auto">
          <div className="flex justify-between items-end mb-12">
            <div>
