          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {PORTFOLIO_IMAGES.map((url, idx) => (
              <div key={idx} className="group relative aspect-[3/4] rounded-3xl overflow-hidden shadow-lg cursor-pointer">
