  const getHourPrice = (isSecond: boolean) => isSecond ? PRICING.HOUR_PRICE * 2 : PRICING.HOUR_PRICE;

  const currentHourPrice = useMemo(() => getHourPrice(selection.secondPhotographer), [selection.secondPhotographer]);

  const calculateTotal = useCallback((sel: Selection) => {
    const hourPrice = getHourPrice(sel.secondPhotographer);
    return (
      (sel.hoursEnabled ? sel.hours * hourPrice : 0) +
      (sel.sessionsEnabled ? sel.sessions * PRICING.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * PRICING.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * PRICING.DRONE_PRICE : 0)
    );
  }, []);

  const calculateMinBudget = useCallback((sel: Selection) => {
    const hourPrice = getHourPrice(sel.secondPhotographer);
    const fixedCosts = 
      (sel.sessionsEnabled ? sel.sessions * PRICING.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * PRICING.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * PRICING.DRONE_PRICE : 0);
    // Photography hours minimum value is 2
    return fixedCosts + (2 * hourPrice);
  }, []);

  // The slider should never go below the cost of fixed items + 2 hours
  const minBudgetAllowed = useMemo(() => calculateMinBudget(selection), [selection, calculateMinBudget]);

