        {grandTotal !== undefined && (
          <div className="mt-6 pt-6 border-t border-primary/10">
            {selectedOptionsSummary && (selectedOptionsSummary.photo.length > 0 || selectedOptionsSummary.video.length > 0) && (
              <div className="mb-8">
                <p className="text-xs uppercase tracking-widest text-gray-400 font-black mb-4">Selected Package Summary</p>

                <div className="space-y-6">
                  {selectedOptionsSummary.photo.length > 0 && (
                    <div>
                      <p className="text-[10px] uppercase tracking-wider text-accent font-bold mb-2">Photo services</p>
                      <ul className="grid grid-cols-1 sm:grid-cols-2 gap-x-4 gap-y-1">
                        {selectedOptionsSummary.photo.map((opt, idx) => (
                          <li key={idx} className="text-xs text-gray-600 flex items-center space-x-2">
                            <span className="w-1 h-1 rounded-full bg-accent/40 block"></span>
                            <span>{opt}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
