              <button 
                onClick={() => handleAdjust(item.id, -1)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-sm"
                aria-label="Decrease"
              >
                -
              </button>
              <span className="text-xl font-serif font-bold text-primary px-3">
                {item.count}
              </span>
              <button 
                onClick={() => handleAdjust(item.id, 1)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-sm"
                aria-label="Increase"
              >
                +
              </button>
            </div>

            {item.id === 'hours' && (
              <div className="mt-3 space-y-1.5">
                <label className="flex items-center space-x-2 cursor-pointer group/check">
                  <input 
                    type="checkbox"
                    checked={selection.secondSpecialist}
                    onChange={(e) => onUpdate({ secondSpecialist: e.target.checked })}
                    className="w-3.5 h-3.5 accent-accent rounded"
                  />
                  <span className="text-[9px] font-bold uppercase tracking-wider text-gray-600 group-hover/check:text-accent transition-colors">
                    {labels.specialist}
