import React, { useMemo } from 'react';

interface EventSchedulingProps {
  date: string; // Expected format: YYYY-MM-DD
  startTime: string;
  endTime: string;
  onUpdate: (data: { date?: string; startTime?: string; endTime?: string }) => void;
}

const EventScheduling: React.FC<EventSchedulingProps> = ({ date, startTime, endTime, onUpdate }) => {
  const times = useMemo(() => {
    const list = [];
    for (let h = 0; h < 24; h++) {
      for (let m = 0; m < 60; m += 30) {
        const hour = h.toString().padStart(2, '0');
        const minute = m.toString().padStart(2, '0');
        list.push(`${hour}:${minute}`);
      }
    }
    return list;
  }, []);

  // Parse the current date string
  const [currentYear, currentMonth, currentDay] = useMemo(() => {
    const parts = date.split('-');
    return [parts[0], parts[1], parts[2]];
  }, [date]);

  const years = useMemo(() => {
    const current = new Date().getFullYear();
    return Array.from({ length: 5 }, (_, i) => (current + i).toString());
  }, []);

  const months = [
    { val: '01', name: 'January' }, { val: '02', name: 'February' }, { val: '03', name: 'March' },
    { val: '04', name: 'April' }, { val: '05', name: 'May' }, { val: '06', name: 'June' },
    { val: '07', name: 'July' }, { val: '08', name: 'August' }, { val: '09', name: 'September' },
    { val: '10', name: 'October' }, { val: '11', name: 'November' }, { val: '12', name: 'December' }
  ];

  const days = useMemo(() => {
    const yearNum = parseInt(currentYear);
    const monthNum = parseInt(currentMonth);
    const lastDay = new Date(yearNum, monthNum, 0).getDate();
    return Array.from({ length: lastDay }, (_, i) => (i + 1).toString().padStart(2, '0'));
  }, [currentYear, currentMonth]);

  const handleDatePartChange = (part: 'year' | 'month' | 'day', value: string) => {
    let y = currentYear;
    let m = currentMonth;
    let d = currentDay;

    if (part === 'year') y = value;
    if (part === 'month') m = value;
    if (part === 'day') d = value;

    // Ensure day is valid for the new month/year
    const lastDay = new Date(parseInt(y), parseInt(m), 0).getDate();
    if (parseInt(d) > lastDay) {
      d = lastDay.toString().padStart(2, '0');
    }

    onUpdate({ date: `${y}-${m}-${d}` });
  };

  const calculateDuration = () => {
    if (!startTime || !endTime) return null;
    const [h1, m1] = startTime.split(':').map(Number);
    const [h2, m2] = endTime.split(':').map(Number);
    const startMins = h1 * 60 + m1;
    const endMins = h2 * 60 + m2;
    const diff = endMins - startMins;
    if (diff <= 0) return null;
    const hours = Math.floor(diff / 60);
    const mins = diff % 60;
    return mins > 0 ? `${hours}h ${mins}m` : `${hours} hours`;
  };

  const duration = calculateDuration();

  const selectBaseStyles = "bg-gray-50 border border-gray-100 rounded-2xl px-4 py-4 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium appearance-none cursor-pointer text-sm";

  return (
    <div className="w-full mb-16">
      <div className="text-center mb-10">
        <h2 className="text-4xl md:text-5xl font-serif font-bold text-primary mb-4">Choose your perfect day</h2>
        <div className="w-20 h-[2px] bg-accent mx-auto"></div>
      </div>

      <div className="bg-white border border-gray-100 shadow-xl rounded-[2.5rem] p-8 md:p-12">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-end">
          <div className="space-y-3">
            <label className="text-xs font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">📅</span> Select Date
            </label>
            <div className="flex gap-2">
              <select 
                value={currentDay}
                onChange={(e) => handleDatePartChange('day', e.target.value)}
                className={`${selectBaseStyles} flex-1`}
              >
                {days.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
              <select 
                value={currentMonth}
                onChange={(e) => handleDatePartChange('month', e.target.value)}
                className={`${selectBaseStyles} flex-[2]`}
              >
                {months.map(m => <option key={m.val} value={m.val}>{m.name}</option>)}
              </select>
              <select 
                value={currentYear}
                onChange={(e) => handleDatePartChange('year', e.target.value)}
                className={`${selectBaseStyles} flex-1`}
              >
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">🕒</span> Starting Hour
            </label>
            <select
              value={startTime}
              onChange={(e) => onUpdate({ startTime: e.target.value })}
              className={`${selectBaseStyles} w-full`}
            >
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="space-y-3 relative">
            <label className="text-xs font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">🕕</span> Ending Hour
            </label>
            <select
              value={endTime}
              onChange={(e) => onUpdate({ endTime: e.target.value })}
              className={`${selectBaseStyles} w-full`}
            >
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
            {duration && (
              <div className="absolute -bottom-8 right-0 text-[10px] font-bold text-accent uppercase tracking-tighter">
                Session Duration: {duration}
              </div>
            )}
          </div>
        </div>

        {startTime >= endTime && startTime !== '00:00' && (
          <p className="text-[10px] text-red-500 mt-6 text-center italic">
            Note: Ending hour should be after starting hour for accurate planning.
          </p>
        )}
      </div>
    </div>
  );
};

