import React, { useMemo } from 'react';

interface EventSchedulingProps {
  date: string;
  startTime: string;
  endTime: string;
  photoEnabled: boolean;
  videoEnabled: boolean;
  contentEnabled: boolean;
  onUpdate: (data: { date?: string; startTime?: string; endTime?: string }) => void;
  onTogglePhoto: (val: boolean) => void;
  onToggleVideo: (val: boolean) => void;
  onToggleContent: (val: boolean) => void;
}

const EventScheduling: React.FC<EventSchedulingProps> = ({ 
  date, 
  startTime, 
  endTime, 
  photoEnabled,
  videoEnabled,
  contentEnabled,
  onUpdate,
  onTogglePhoto,
  onToggleVideo,
  onToggleContent
}) => {
  const times = useMemo(() => {
    const list = [];
    for (let h = 0; h < 24; h++) {
      for (let m = 0; m < 60; m += 30) {
        const hour = h.toString().padStart(2, '0');
        const minute = m.toString().padStart(2, '0');
        list.push(`${hour}:${minute}`);
      }
    }
    return list;
  }, []);

  const [currentYear, currentMonth, currentDay] = useMemo(() => {
    const parts = date.split('-');
    return [parts[0], parts[1], parts[2]];
  }, [date]);

  const years = useMemo(() => {
    const current = new Date().getFullYear();
    return Array.from({ length: 5 }, (_, i) => (current + i).toString());
  }, []);

  const months = [
    { val: '01', name: 'Jan' }, { val: '02', name: 'Feb' }, { val: '03', name: 'Mar' },
    { val: '04', name: 'Apr' }, { val: '05', name: 'May' }, { val: '06', name: 'Jun' },
    { val: '07', name: 'Jul' }, { val: '08', name: 'Aug' }, { val: '09', name: 'Sep' },
    { val: '10', name: 'Oct' }, { val: '11', name: 'Nov' }, { val: '12', name: 'Dec' }
  ];

  const days = useMemo(() => {
    const yearNum = parseInt(currentYear);
    const monthNum = parseInt(currentMonth);
    const lastDay = new Date(yearNum, monthNum, 0).getDate();
    return Array.from({ length: lastDay }, (_, i) => (i + 1).toString().padStart(2, '0'));
  }, [currentYear, currentMonth]);

  const handleDatePartChange = (part: 'year' | 'month' | 'day', value: string) => {
    let y = currentYear;
    let m = currentMonth;
    let d = currentDay;
    if (part === 'year') y = value;
    if (part === 'month') m = value;
    if (part === 'day') d = value;
    const lastDay = new Date(parseInt(y), parseInt(m), 0).getDate();
    if (parseInt(d) > lastDay) d = lastDay.toString().padStart(2, '0');
    onUpdate({ date: `${y}-${m}-${d}` });
  };

  const calculateDuration = () => {
    if (!startTime || !endTime) return null;
    const [h1, m1] = startTime.split(':').map(Number);
    const [h2, m2] = endTime.split(':').map(Number);
    const startMins = h1 * 60 + m1;
    const endMins = h2 * 60 + m2;
    const diff = endMins - startMins;
    if (diff <= 0) return null;
    const hours = Math.floor(diff / 60);
    const mins = diff % 60;
    return mins > 0 ? `${hours}h ${mins}m` : `${hours} hours`;
  };

  const duration = calculateDuration();
  const selectBaseStyles = "bg-gray-50 border border-gray-100 rounded-2xl px-3 py-3.5 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium appearance-none cursor-pointer text-sm w-full";

  return (
    <div className="w-full mb-16">
      <div className="text-center mb-10">
        <h2 className="text-4xl md:text-5xl font-serif font-bold text-primary mb-4">Choose your perfect day</h2>
        <div className="w-20 h-[2px] bg-accent mx-auto"></div>
      </div>

      <div className="bg-white border border-gray-100 shadow-xl rounded-[2.5rem] p-8 md:p-10 space-y-10">
        {/* Date and Time Row */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-end">
          <div className="space-y-3">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">📅</span> Event Date
            </label>
            <div className="flex gap-2">
              <select value={currentDay} onChange={(e) => handleDatePartChange('day', e.target.value)} className={selectBaseStyles}>
                {days.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
              <select value={currentMonth} onChange={(e) => handleDatePartChange('month', e.target.value)} className={selectBaseStyles}>
                {months.map(m => <option key={m.val} value={m.val}>{m.name}</option>)}
              </select>
              <select value={currentYear} onChange={(e) => handleDatePartChange('year', e.target.value)} className={selectBaseStyles}>
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">🕒</span> Start Time
            </label>
            <select value={startTime} onChange={(e) => onUpdate({ startTime: e.target.value })} className={selectBaseStyles}>
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="space-y-3 relative">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              <span className="mr-2">🕕</span> End Time
            </label>
            <select value={endTime} onChange={(e) => onUpdate({ endTime: e.target.value })} className={selectBaseStyles}>
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
            {duration && (
              <div className="absolute -bottom-6 right-0 text-[9px] font-bold text-accent uppercase tracking-tighter bg-accent/5 px-2 py-0.5 rounded-full">
                Duration: {duration}
              </div>
            )}
          </div>
        </div>

        {/* Service Toggles Row */}
        <div className="pt-8 border-t border-gray-100">
          <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-400 mb-6 text-center">Include Services</p>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${photoEnabled ? 'bg-accent/5 border-accent shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className="text-xl">📸</span>
                <span className={`text-xs font-bold uppercase tracking-widest ${photoEnabled ? 'text-primary' : 'text-gray-400'}`}>Photography</span>
              </div>
              <input type="checkbox" checked={photoEnabled} onChange={(e) => onTogglePhoto(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>

            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${videoEnabled ? 'bg-accent/5 border-accent shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className="text-xl">🎥</span>
                <span className={`text-xs font-bold uppercase tracking-widest ${videoEnabled ? 'text-primary' : 'text-gray-400'}`}>Videography</span>
              </div>
              <input type="checkbox" checked={videoEnabled} onChange={(e) => onToggleVideo(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>

            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${contentEnabled ? 'bg-accent/5 border-accent/40 shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className="text-xl">📱</span>
                <span className={`text-xs font-bold uppercase tracking-widest ${contentEnabled ? 'text-primary' : 'text-gray-400'}`}>Content Creator</span>
              </div>
              <input type="checkbox" checked={contentEnabled} onChange={(e) => onToggleContent(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>
          </div>
        </div>

        {startTime >= endTime && startTime !== '00:00' && (
          <p className="text-[10px] text-red-500 mt-2 text-center italic font-medium">
            ⚠️ Warning: Ending hour should be after starting hour.
          </p>
        )}
      </div>
    </div>
  );
};

export default EventScheduling;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import PriceSlider from './components/PriceSlider';
import BudgetAllocation from './components/BudgetAllocation';
import ChatAssistant from './components/ChatAssistant';
import EventScheduling from './components/EventScheduling';
import { PORTFOLIO_IMAGES, PHOTO_PRICING, VIDEO_PRICING, CONTENT_PRICING } from './constants';
import { Selection, PricingConstants } from './types';

const App: React.FC = () => {
  // Helper to calculate hours from time strings
  const getDurationHours = (start: string, end: string): number => {
    const [h1, m1] = start.split(':').map(Number);
    const [h2, m2] = end.split(':').map(Number);
    const diff = (h2 * 60 + m2) - (h1 * 60 + m1);
    return diff > 0 ? diff / 60 : 0;
  };

  // Scheduling State
  const [eventSchedule, setEventSchedule] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '10:00',
    endTime: '18:00',
  });

  const scheduleDuration = useMemo(() => 
    getDurationHours(eventSchedule.startTime, eventSchedule.endTime), 
    [eventSchedule.startTime, eventSchedule.endTime]
  );

  // Photography State
  const [photoBudget, setPhotoBudget] = useState(50);
  const [photoSelection, setPhotoSelection] = useState<Selection>({
    hours: 8, // Initialized to match default 10:00-18:00 (8h)
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Videography State
  const [videoBudget, setVideoBudget] = useState(50);
  const [videoSelection, setVideoSelection] = useState<Selection>({
    hours: 8,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Content Creator State
  const [contentBudget, setContentBudget] = useState(50);
  const [contentSelection, setContentSelection] = useState<Selection>({
    hours: 8,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: false,
    sessionsEnabled: false,
    hoursEnabled: true,
    droneEnabled: false,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  const getHourPrice = useCallback((isSecond: boolean, pricing: PricingConstants) => 
    isSecond ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE, []);

  const calculateTotal = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    return (
      (sel.hoursEnabled ? sel.hours * hourPrice : 0) +
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0)
    );
  }, [getHourPrice]);

  const calculateMinBudget = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    const fixedCosts = 
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0);
    // Respect the 2-hour minimum or the schedule duration, whichever is greater
    const effectiveHours = Math.max(2, sel.hours);
    return fixedCosts + (effectiveHours * hourPrice);
  }, [getHourPrice]);

  // Handle schedule changes and sync hours
  const handleScheduleUpdate = (data: { date?: string; startTime?: string; endTime?: string }) => {
    const nextSchedule = { ...eventSchedule, ...data };
    setEventSchedule(nextSchedule);

    const newDuration = getDurationHours(nextSchedule.startTime, nextSchedule.endTime);
    if (newDuration > 0) {
      // If duration is valid, we update the service hours automatically
      // We only update if the new duration is greater than or equal to the 2-hour minimum usually
      // But per prompt "if Duration is bigger than minimum hours", we sync it.
      const syncedHours = Math.max(2, newDuration);

      handlePhotoUpdate({ hours: syncedHours });
      handleVideoUpdate({ hours: syncedHours });
      handleContentUpdate({ hours: syncedHours });
    }
  };

  const currentPhotoTotal = useMemo(() => calculateTotal(photoSelection, PHOTO_PRICING), [photoSelection, calculateTotal]);
  const currentVideoTotal = useMemo(() => calculateTotal(videoSelection, VIDEO_PRICING), [videoSelection, calculateTotal]);
  const currentContentTotal = useMemo(() => calculateTotal(contentSelection, CONTENT_PRICING), [contentSelection, calculateTotal]);

  const allSummary = useMemo(() => {
    const photo: string[] = [];
    const video: string[] = [];
    const content: string[] = [];

    if (photoSelection.serviceEnabled) {
      if (photoSelection.hours > 0) {
        const specialistCount = photoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Photographer' : 'Photographers';
        photo.push(`${specialistCount} ${label} for ${photoSelection.hours} Hours`);
      }
      if (photoSelection.sessions > 0) photo.push(`${photoSelection.sessions} Photo-Session(s)`);
      if (photoSelection.books > 0) photo.push(`${photoSelection.books} Photo-Book(s)`);
      if (photoSelection.droneSessions > 0) photo.push(`${photoSelection.droneSessions} Drone Photo Session(s)`);
    }

    if (videoSelection.serviceEnabled) {
      if (videoSelection.hours > 0) {
        const specialistCount = videoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Videographer' : 'Videographers';
        video.push(`${specialistCount} ${label} for ${videoSelection.hours} Hours`);
      }
      if (videoSelection.sessions > 0) video.push(`${videoSelection.sessions} Love-Story(ies)`);
      if (videoSelection.books > 0) video.push(`${videoSelection.books} Crane Location(s)`);
      if (videoSelection.droneSessions > 0) video.push(`${videoSelection.droneSessions} Drone Video Session(s)`);
    }

    if (contentSelection.serviceEnabled) {
      if (contentSelection.hours > 0) {
        content.push(`${contentSelection.hours} Hours of Content Creation`);
      }
    }

    return { photo, video, content };
  }, [photoSelection, videoSelection, contentSelection]);

  // State update wrappers that ensure budget follows selection
  const handlePhotoUpdate = (update: Partial<Selection>) => {
    setPhotoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, PHOTO_PRICING);
      const newMin = calculateMinBudget(next, PHOTO_PRICING);
      setPhotoBudget(prevBudget => Math.max(newMin, newTotal, prevBudget));
      return next;
    });
  };

  const handleVideoUpdate = (update: Partial<Selection>) => {
    setVideoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, VIDEO_PRICING);
      const newMin = calculateMinBudget(next, VIDEO_PRICING);
      setVideoBudget(prevBudget => Math.max(newMin, newTotal, prevBudget));
      return next;
    });
  };

  const handleContentUpdate = (update: Partial<Selection>) => {
    setContentSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, CONTENT_PRICING);
      const newMin = calculateMinBudget(next, CONTENT_PRICING);
      setContentBudget(prevBudget => Math.max(newMin, newTotal, prevBudget));
      return next;
    });
  };

  const handlePhotoSliderChange = (newVal: number) => {
    if (!photoSelection.serviceEnabled) return;
    const min = calculateMinBudget(photoSelection, PHOTO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setPhotoBudget(effectiveVal);

    setPhotoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * PHOTO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * PHOTO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * PHOTO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = effectiveVal - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, PHOTO_PRICING);
      // Ensure we don't drop below the schedule duration
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleVideoSliderChange = (newVal: number) => {
    if (!videoSelection.serviceEnabled) return;
    const min = calculateMinBudget(videoSelection, VIDEO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setVideoBudget(effectiveVal);

    setVideoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * VIDEO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * VIDEO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * VIDEO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = effectiveVal - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, VIDEO_PRICING);
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleContentSliderChange = (newVal: number) => {
    if (!contentSelection.serviceEnabled) return;
    const min = calculateMinBudget(contentSelection, CONTENT_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setContentBudget(effectiveVal);

    setPhotoSelection(prev => {
      const remainingBudget = effectiveVal;
      const hourPrice = CONTENT_PRICING.HOUR_PRICE;
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const grandTotal = currentPhotoTotal + currentVideoTotal + currentContentTotal;

  return (
