export const CONTENT_PRICING: PricingConstants = {
  HOUR_PRICE: 25,
  SESSION_PRICE: 0,
  BOOK_PRICE: 0,
  DRONE_PRICE: 0,
  MIN_BUDGET: 50,
  STEP: 25,
