import React, { useState, useCallback, useMemo } from 'react';
import PriceSlider from './components/PriceSlider';
import BudgetAllocation from './components/BudgetAllocation';
import ChatAssistant from './components/ChatAssistant';
import EventScheduling from './components/EventScheduling';
import { PORTFOLIO_IMAGES, PHOTO_PRICING, VIDEO_PRICING, CONTENT_PRICING, COST_MULTIPLIER } from './constants';
import { Selection, PricingConstants } from './types';

const App: React.FC = () => {
  // Helper to calculate hours from time strings, handling cross-midnight intervals
  const getDurationHours = (start: string, end: string): number => {
    const [h1, m1] = start.split(':').map(Number);
    const [h2, m2] = end.split(':').map(Number);
    let startMins = h1 * 60 + m1;
    let endMins = h2 * 60 + m2;

    // If end time is before or same as start time, assume it's the next day
    if (endMins <= startMins) {
      endMins += 24 * 60;
    }

    return (endMins - startMins) / 60;
  };

  // Scheduling State - Initialized to 12:00 - 14:00 (2 hours)
  const [eventSchedule, setEventSchedule] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '12:00',
    endTime: '14:00',
  });

  const scheduleDuration = useMemo(() => 
    getDurationHours(eventSchedule.startTime, eventSchedule.endTime), 
    [eventSchedule.startTime, eventSchedule.endTime]
  );

  // Photography State - Initialized to 2h * $25 = $50
  const [photoBudget, setPhotoBudget] = useState(50);
  const [photoSelection, setPhotoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Videography State - Initialized to 2h * $25 = $50
  const [videoBudget, setVideoBudget] = useState(50);
  const [videoSelection, setVideoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Content Creator State - Initialized to 2h * $25 = $50
  const [contentBudget, setContentBudget] = useState(50);
  const [contentSelection, setContentSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: false,
    sessionsEnabled: false,
    hoursEnabled: true,
    droneEnabled: false,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  const getHourPrice = useCallback((isSecond: boolean, pricing: PricingConstants) => 
    isSecond ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE, []);

  const calculateTotal = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    const baseTotal = (
      (sel.hoursEnabled ? sel.hours * hourPrice : 0) +
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0)
    );
    return Math.round(baseTotal * COST_MULTIPLIER);
  }, [getHourPrice]);

  const calculateMinBudget = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    const fixedCosts = 
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0);
    const effectiveHours = Math.max(2, sel.hours);
    return Math.round((fixedCosts + (effectiveHours * hourPrice)) * COST_MULTIPLIER);
  }, [getHourPrice]);

  // Unified update functions that can optionally force-sync the budget
  const updatePhoto = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setPhotoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, PHOTO_PRICING);
      const newMin = calculateMinBudget(next, PHOTO_PRICING);
      setPhotoBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  const updateVideo = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setVideoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, VIDEO_PRICING);
      const newMin = calculateMinBudget(next, VIDEO_PRICING);
      setVideoBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  const updateContent = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setContentSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, CONTENT_PRICING);
      const newMin = calculateMinBudget(next, CONTENT_PRICING);
      setContentBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  // Handle schedule changes and sync hours + budget
  const handleScheduleUpdate = (data: { date?: string; startTime?: string; endTime?: string }) => {
    const nextSchedule = { ...eventSchedule, ...data };
    setEventSchedule(nextSchedule);

    const newDuration = getDurationHours(nextSchedule.startTime, nextSchedule.endTime);
    const syncedHours = Math.max(2, newDuration);

    // Update hours and reset budget to exactly match the new total cost
    updatePhoto({ hours: syncedHours }, true);
    updateVideo({ hours: syncedHours }, true);
    updateContent({ hours: syncedHours }, true);
  };

  const currentPhotoTotal = useMemo(() => calculateTotal(photoSelection, PHOTO_PRICING), [photoSelection, calculateTotal]);
  const currentVideoTotal = useMemo(() => calculateTotal(videoSelection, VIDEO_PRICING), [videoSelection, calculateTotal]);
  const currentContentTotal = useMemo(() => calculateTotal(contentSelection, CONTENT_PRICING), [contentSelection, calculateTotal]);

  const allSummary = useMemo(() => {
    const photo: string[] = [];
    const video: string[] = [];
    const content: string[] = [];

    if (photoSelection.serviceEnabled) {
      if (photoSelection.hours > 0) {
        const specialistCount = photoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Photographer' : 'Photographers';
        photo.push(`${specialistCount} ${label} for ${photoSelection.hours} Hours`);
      }
      if (photoSelection.sessions > 0) photo.push(`${photoSelection.sessions} Photo-Session(s)`);
      if (photoSelection.books > 0) photo.push(`${photoSelection.books} Photo-Book(s)`);
      if (photoSelection.droneSessions > 0) photo.push(`${photoSelection.droneSessions} Drone Photo Session(s)`);
    }

    if (videoSelection.serviceEnabled) {
      if (videoSelection.hours > 0) {
        const specialistCount = videoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Videographer' : 'Videographers';
        video.push(`${specialistCount} ${label} for ${videoSelection.hours} Hours`);
      }
      if (videoSelection.sessions > 0) video.push(`${videoSelection.sessions} Love-Story(ies)`);
      if (videoSelection.books > 0) video.push(`${videoSelection.books} Crane Location(s)`);
      if (videoSelection.droneSessions > 0) video.push(`${videoSelection.droneSessions} Drone Video Session(s)`);
    }

    if (contentSelection.serviceEnabled) {
      if (contentSelection.hours > 0) {
        content.push(`${contentSelection.hours} Hours of Content Creation`);
      }
    }

    return { photo, video, content };
  }, [photoSelection, videoSelection, contentSelection]);

  const handlePhotoSliderChange = (newVal: number) => {
    if (!photoSelection.serviceEnabled) return;
    const min = calculateMinBudget(photoSelection, PHOTO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setPhotoBudget(effectiveVal);

    setPhotoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * PHOTO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * PHOTO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * PHOTO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = (effectiveVal / COST_MULTIPLIER) - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, PHOTO_PRICING);
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleVideoSliderChange = (newVal: number) => {
    if (!videoSelection.serviceEnabled) return;
    const min = calculateMinBudget(videoSelection, VIDEO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setVideoBudget(effectiveVal);

    setVideoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * VIDEO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * VIDEO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * VIDEO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = (effectiveVal / COST_MULTIPLIER) - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, VIDEO_PRICING);
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleContentSliderChange = (newVal: number) => {
    if (!contentSelection.serviceEnabled) return;
    const min = calculateMinBudget(contentSelection, CONTENT_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setContentBudget(effectiveVal);

    setContentSelection(prev => {
      const remainingBudget = (effectiveVal / COST_MULTIPLIER);
      const hourPrice = CONTENT_PRICING.HOUR_PRICE;
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const grandTotal = currentPhotoTotal + currentVideoTotal + currentContentTotal;

  return (
    <div className="min-h-screen flex flex-col font-sans text-primary">
      <nav className="fixed top-0 w-full z-50 glass-morphism border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <span className="text-white font-serif font-bold italic">L</span>
            </div>
            <span className="font-serif text-xl font-bold tracking-tight">LUMINA FRAMES</span>
          </div>
          <div className="hidden md:flex space-x-8 text-sm font-medium text-gray-600">
            <a href="#" className="hover:text-accent transition-colors">Portfolio</a>
            <a href="#planner" className="hover:text-accent transition-colors">Pricing</a>
            <a href="#" className="hover:text-accent transition-colors">Our Studio</a>
            <button className="bg-primary text-white px-6 py-2 rounded-full text-xs uppercase tracking-widest hover:bg-accent transition-all">Book Now</button>
          </div>
        </div>
      </nav>

      <header className="pt-32 pb-20 px-6 bg-[#fafafa]">
        <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-12 items-center">
          <div className="space-y-8">
            <h1 className="text-6xl md:text-7xl font-serif font-bold leading-tight">
              Capturing <br />
              <span className="text-accent italic">Timeless</span> <br />
              Moments.
            </h1>
            <p className="text-lg text-gray-500 max-w-md leading-relaxed">
              Professional media services tailored to your budget. From photography to cinematic videography, we frame your story with elegance.
            </p>
            <div className="flex space-x-4">
              <a href="#planner" className="bg-primary text-white px-8 py-4 rounded-full font-medium hover:bg-gray-800 transition-all shadow-lg">Plan Your Session</a>
              <a href="#portfolio" className="border border-gray-300 px-8 py-4 rounded-full font-medium hover:bg-gray-50 transition-all">View Work</a>
            </div>
          </div>
          <div className="relative">
            <div className="aspect-[4/5] rounded-3xl overflow-hidden shadow-2xl">
              <img 
                src="https://images.unsplash.com/photo-1554080353-a576cf803bda?auto=format&fit=crop&q=80&w=1200" 
                alt="Professional camera" 
                className="w-full h-full object-cover"
              />
            </div>
          </div>
        </div>
      </header>

      <section id="planner" className="py-24 px-6 bg-white">
        <div className="max-w-7xl mx-auto space-y-32">

          <EventScheduling 
            date={eventSchedule.date}
            startTime={eventSchedule.startTime}
            endTime={eventSchedule.endTime}
            photoEnabled={photoSelection.serviceEnabled}
            videoEnabled={videoSelection.serviceEnabled}
            contentEnabled={contentSelection.serviceEnabled}
            onUpdate={handleScheduleUpdate}
            onTogglePhoto={(val) => updatePhoto({ serviceEnabled: val }, true)}
            onToggleVideo={(val) => updateVideo({ serviceEnabled: val }, true)}
            onToggleContent={(val) => updateContent({ serviceEnabled: val }, true)}
          />

          <div className={`grid lg:grid-cols-3 gap-12 items-start transition-all duration-500 ${!photoSelection.serviceEnabled ? 'hidden' : ''}`}>
            <div className="lg:col-span-2 bg-gray-50/50 p-8 md:p-12 rounded-[2rem] border border-gray-100">
              <div className="mb-12 text-center">
                <div className="flex flex-col items-center mb-8">
                  <span className="text-3xl uppercase tracking-[0.3em] text-gray-400 font-bold mb-4">PHOTOGRAPHY</span>
                  <div className="w-24 h-[1px] bg-accent/30"></div>
                </div>
                <h3 className="text-sm font-bold uppercase tracking-widest text-accent mb-6">Investment Range</h3>
                <PriceSlider 
                  value={photoBudget} 
                  onChange={handlePhotoSliderChange} 
                  min={calculateMinBudget(photoSelection, PHOTO_PRICING)}
                  title="Your Investment into Photography"
                />
              </div>
              <div className="pt-8 border-t border-gray-200">
                <BudgetAllocation 
                  selection={photoSelection} 
                  onUpdate={(upd) => updatePhoto(upd)} 
                  maxBudget={photoBudget}
                  pricing={PHOTO_PRICING}
                  type="photo"
                />
              </div>
            </div>
            <div className="space-y-6">
              <div className="bg-accent/5 p-8 rounded-[2rem] border border-accent/10">
                <h3 className="text-xl font-serif font-bold mb-2">Photo Consultation</h3>
                <ChatAssistant budget={photoBudget} />
              </div>
            </div>
          </div>

          <div className={`grid lg:grid-cols-3 gap-12 items-start transition-all duration-500 ${!videoSelection.serviceEnabled ? 'hidden' : ''}`}>
            <div className="lg:col-span-2 bg-gray-50/50 p-8 md:p-12 rounded-[2rem] border border-gray-100">
              <div className="mb-12 text-center">
                <div className="flex flex-col items-center mb-8">
                  <span className="text-3xl uppercase tracking-[0.3em] text-gray-400 font-bold mb-4">VIDEOGRAPHY</span>
                  <div className="w-24 h-[1px] bg-accent/30"></div>
                </div>
                <h3 className="text-sm font-bold uppercase tracking-widest text-accent mb-6">Investment Range</h3>
                <PriceSlider 
                  value={videoBudget} 
                  onChange={handleVideoSliderChange} 
                  min={calculateMinBudget(videoSelection, VIDEO_PRICING)}
                  title="Your Investment into Videography"
                />
              </div>
              <div className="pt-8 border-t border-gray-200">
                <BudgetAllocation 
                  selection={videoSelection} 
                  onUpdate={(upd) => updateVideo(upd)} 
                  maxBudget={videoBudget}
                  pricing={VIDEO_PRICING}
                  type="video"
                />
              </div>
            </div>
            <div className="space-y-6">
              <div className="bg-primary/5 p-8 rounded-[2rem] border border-primary/10">
                <h3 className="text-xl font-serif font-bold mb-2">Video Consultation</h3>
                <ChatAssistant budget={videoBudget} />
              </div>
            </div>
          </div>

          <div className={`grid lg:grid-cols-3 gap-12 items-start transition-all duration-500 ${!contentSelection.serviceEnabled ? 'hidden' : ''}`}>
            <div className="lg:col-span-2 bg-gray-50/50 p-8 md:p-12 rounded-[2rem] border border-gray-100">
              <div className="mb-12 text-center">
                <div className="flex flex-col items-center mb-8">
                  <span className="text-3xl uppercase tracking-[0.3em] text-gray-400 font-bold mb-4">CONTENT CREATOR</span>
                  <div className="w-24 h-[1px] bg-accent/30"></div>
                </div>
                <h3 className="text-sm font-bold uppercase tracking-widest text-accent mb-6">Investment Range</h3>
                <PriceSlider 
                  value={contentBudget} 
                  onChange={handleContentSliderChange} 
                  min={calculateMinBudget(contentSelection, CONTENT_PRICING)}
                  title="Your Investment into Content Creation"
                />
              </div>
              <div className="pt-8 border-t border-gray-200">
                <BudgetAllocation 
                  selection={contentSelection} 
                  onUpdate={(upd) => updateContent(upd)} 
                  maxBudget={contentBudget}
                  pricing={CONTENT_PRICING}
                  type="content"
                  showSpecialist={false}
                  allowedItems={['hours']}
                />
              </div>
            </div>
            <div className="space-y-6">
              <div className="bg-accent/5 p-8 rounded-[2rem] border border-accent/10">
                <h3 className="text-xl font-serif font-bold mb-2">Creation Strategy</h3>
                <ChatAssistant budget={contentBudget} />
              </div>
            </div>
          </div>

          <div className="grid lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2 space-y-8">
              <div className="flex items-center space-x-6 opacity-40">
                <div className="h-[1px] flex-1 bg-gradient-to-r from-transparent to-primary/40"></div>
                <div className="flex items-center space-x-1.5">
                  <div className="w-1 h-1 rotate-45 border border-primary/60 bg-white"></div>
                  <div className="w-1.5 h-1.5 rotate-45 border border-primary/80 bg-primary"></div>
                  <div className="w-1 h-1 rotate-45 border border-primary/60 bg-white"></div>
                </div>
                <div className="h-[1px] flex-1 bg-gradient-to-l from-transparent to-primary/40"></div>
              </div>

              <div className={`p-8 md:p-12 rounded-[3rem] border transition-all shadow-xl overflow-hidden relative group bg-accent/15 border-accent/30`}>
                <div className="absolute top-0 right-0 w-64 h-64 bg-accent/10 blur-[120px] rounded-full -mr-20 -mt-20"></div>
                <div className="relative z-10">
                  {(allSummary.photo.length > 0 || allSummary.video.length > 0 || allSummary.content.length > 0) && (
                    <div className="mb-12">
                      <p className="text-xs uppercase tracking-[0.2em] text-primary font-black mb-8 border-b border-primary/10 pb-4">Selected Package Summary</p>

                      <div className="grid md:grid-cols-3 gap-10">
                        {allSummary.photo.length > 0 && (
                          <div className="space-y-4">
                            <p className="text-[15px] uppercase tracking-widest text-black font-black">Photo services</p>
                            <ul className="space-y-3">
                              {allSummary.photo.map((opt, idx) => (
                                <li key={idx} className="text-xs text-gray-800 flex items-start space-x-3 leading-relaxed font-medium">
                                  <span className="w-1.5 h-1.5 rounded-full bg-accent mt-1 flex-shrink-0 shadow-sm"></span>
                                  <span>{opt}</span>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}

                        {allSummary.video.length > 0 && (
                          <div className="space-y-4">
                            <p className="text-[15px] uppercase tracking-widest text-black font-black">Video services</p>
                            <ul className="space-y-3">
                              {allSummary.video.map((opt, idx) => (
                                <li key={idx} className="text-xs text-gray-800 flex items-start space-x-3 leading-relaxed font-medium">
                                  <span className="w-1.5 h-1.5 rounded-full bg-primary/40 mt-1 flex-shrink-0"></span>
                                  <span>{opt}</span>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}

                        {allSummary.content.length > 0 && (
                          <div className="space-y-4">
                            <p className="text-[15px] uppercase tracking-widest text-black font-black">Content Creation</p>
                            <ul className="space-y-3">
                              {allSummary.content.map((opt, idx) => (
                                <li key={idx} className="text-xs text-gray-800 flex items-start space-x-3 leading-relaxed font-medium">
                                  <span className="w-1.5 h-1.5 rounded-full bg-accent/60 mt-1 flex-shrink-0"></span>
                                  <span>{opt}</span>
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}
                      </div>
                    </div>
                  )}

                  <div className="pt-8 border-t border-primary/10 flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="text-center md:text-left">
                      <p className="text-xs uppercase tracking-[0.3em] text-gray-500 font-bold mb-3">Total Investment</p>
                      <p className="text-4xl md:text-7xl font-serif font-bold text-primary leading-none tracking-tighter">
                        ${grandTotal}
                      </p>
                    </div>
                    <div className="md:self-end">
                      <button className="bg-primary text-white px-10 py-5 rounded-full font-bold uppercase tracking-widest text-xs hover:scale-105 transition-transform shadow-lg shadow-black/20">
                        Book Your Experience
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <footer className="bg-primary text-white py-20 px-6 mt-20">
        <div className="max-w-7xl mx-auto grid md:grid-cols-4 gap-12">
          <div className="col-span-2 space-y-6">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-accent rounded-lg flex items-center justify-center">
                <span className="text-primary font-serif font-bold italic">L</span>
              </div>
              <span className="font-serif text-2xl font-bold tracking-tight">LUMINA FRAMES</span>
            </div>
            <p className="text-gray-400 max-w-sm leading-relaxed">
              We believe every frame tells a story. Our mission is to provide world-class photography and videography services.
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { Selection, PricingConstants } from '../types';
import { COST_MULTIPLIER } from '../constants';

interface BudgetAllocationProps {
  selection: Selection;
  onUpdate: (update: Partial<Selection>) => void;
  maxBudget: number;
  pricing: PricingConstants;
  type: 'photo' | 'video' | 'content';
  showSpecialist?: boolean;
  allowedItems?: ('hours' | 'sessions' | 'books' | 'droneSessions')[];
}

const BudgetAllocation: React.FC<BudgetAllocationProps> = ({ 
  selection, 
  onUpdate, 
  maxBudget, 
  pricing, 
  type,
  showSpecialist = true,
  allowedItems = ['hours', 'sessions', 'books', 'droneSessions']
}) => {
  const currentHourPrice = selection.secondSpecialist ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE;

  const baseTotalCost = 
    (selection.hoursEnabled ? selection.hours * currentHourPrice : 0) +
    (selection.sessionsEnabled ? selection.sessions * pricing.SESSION_PRICE : 0) +
    (selection.booksEnabled ? selection.books * pricing.BOOK_PRICE : 0) +
    (selection.droneEnabled ? selection.droneSessions * pricing.DRONE_PRICE : 0);

  const actualTotalCost = Math.round(baseTotalCost * COST_MULTIPLIER);

  const labels = {
    hours: type === 'photo' ? 'Photography Hours' : type === 'video' ? 'Videography Hours' : 'Content Creation Hours',
    sessions: type === 'photo' ? 'Photo-Sessions' : 'Love-Story',
    books: type === 'photo' ? 'Photo-Books' : 'Crane',
    drone: type === 'photo' ? 'Drone Photography' : 'Drone Videography',
    specialist: type === 'photo' ? 'Second Photographer' : 'Second Videographer',
    totalCost: type === 'photo' ? 'Total estimated cost for Photography' : type === 'video' ? 'Total estimated cost for Videography' : 'Total estimated cost for Content Creation'
  };

  const allItems = [
    { 
      id: 'hours' as const,
      name: labels.hours, 
      count: selection.hours, 
      enabled: selection.hoursEnabled,
      price: currentHourPrice, 
      unitLabel: 'per hour',
      icon: '⏱️',
      min: 2
    },
    { 
      id: 'sessions' as const,
      name: labels.sessions, 
      count: selection.sessions, 
      enabled: selection.sessionsEnabled,
      price: pricing.SESSION_PRICE, 
      unitLabel: type === 'photo' ? 'per session' : 'per Love-Story',
      icon: type === 'photo' ? '📸' : '🎥',
      min: 0
    },
    { 
      id: 'books' as const,
      name: labels.books, 
      count: selection.books, 
      enabled: selection.booksEnabled,
      price: pricing.BOOK_PRICE, 
      unitLabel: type === 'photo' ? 'per photo-book 30x20cm' : 'per location',
      icon: type === 'photo' ? '📚' : '🏗️',
      min: 0
    },
    { 
      id: 'droneSessions' as const,
      name: labels.drone, 
      count: selection.droneSessions, 
      enabled: selection.droneEnabled,
      price: pricing.DRONE_PRICE, 
      unitLabel: 'per session',
      icon: '🛸',
      min: 0
    },
  ];

  const items = allItems.filter(item => allowedItems.includes(item.id));

  const handleAdjust = (id: string, delta: number) => {
    if (!selection.serviceEnabled) return;
    const currentVal = selection[id as keyof Selection] as number;
    const itemConfig = items.find(item => item.id === id);
    const minVal = itemConfig?.min ?? 0;

    const newVal = Math.max(minVal, currentVal + delta);
    const update: any = { [id]: newVal };

    if (id === 'hours') update.hoursEnabled = true;
    if (id === 'sessions') update.sessionsEnabled = true;
    if (id === 'books') update.booksEnabled = true;
    if (id === 'droneSessions') update.droneEnabled = true;

    onUpdate(update);
  };

  return (
    <div className="space-y-8 mt-12">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {items.map((item) => (
          <div 
            key={item.id} 
            className={`relative group overflow-hidden bg-white p-5 rounded-2xl shadow-sm border transition-all hover:shadow-md ${
              item.enabled ? 'border-accent ring-1 ring-accent/20' : 'border-gray-100 opacity-60'
            }`}
          >
            <div className="flex justify-between items-start mb-3">
              <div className="text-2xl">{item.icon}</div>
              <div className="text-lg font-bold text-accent bg-accent/5 px-2.5 py-1 rounded-lg">
                ${Math.round(item.count * item.price * COST_MULTIPLIER)}
              </div>
            </div>

            <h4 className="text-sm font-bold text-gray-800 leading-tight">{item.name}</h4>
            <p className="text-[10px] text-gray-500 mb-4">${item.price} {item.unitLabel}</p>

            <div className="flex items-center justify-between bg-gray-50 rounded-xl p-1.5">
              <button 
                onClick={() => handleAdjust(item.id, -1)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-sm"
                aria-label="Decrease"
              >
                -
              </button>
              <span className="text-xl font-serif font-bold text-primary px-3">
                {item.count}
              </span>
              <button 
                onClick={() => handleAdjust(item.id, 1)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-sm"
                aria-label="Increase"
              >
                +
              </button>
            </div>

