import React, { useMemo } from 'react';

interface EventSchedulingProps {
  date: string;
  startTime: string;
  endTime: string;
  photoEnabled: boolean;
  videoEnabled: boolean;
  contentEnabled: boolean;
  onUpdate: (data: { date?: string; startTime?: string; endTime?: string }) => void;
  onTogglePhoto: (val: boolean) => void;
  onToggleVideo: (val: boolean) => void;
  onToggleContent: (val: boolean) => void;
}

const EventScheduling: React.FC<EventSchedulingProps> = ({ 
  date, 
  startTime, 
  endTime, 
  photoEnabled,
  videoEnabled,
  contentEnabled,
  onUpdate,
  onTogglePhoto,
  onToggleVideo,
  onToggleContent
}) => {
  const times = useMemo(() => {
    const list = [];
    for (let h = 0; h < 24; h++) {
      for (let m = 0; m < 60; m += 30) {
        const hour = h.toString().padStart(2, '0');
        const minute = m.toString().padStart(2, '0');
        list.push(`${hour}:${minute}`);
      }
    }
    return list;
  }, []);

  const [currentYear, currentMonth, currentDay] = useMemo(() => {
    const parts = date.split('-');
    return [parts[0], parts[1], parts[2]];
  }, [date]);

  const years = useMemo(() => {
    const current = new Date().getFullYear();
    return Array.from({ length: 5 }, (_, i) => (current + i).toString());
  }, []);

  const months = [
    { val: '01', name: 'Jan' }, { val: '02', name: 'Feb' }, { val: '03', name: 'Mar' },
    { val: '04', name: 'Apr' }, { val: '05', name: 'May' }, { val: '06', name: 'Jun' },
    { val: '07', name: 'Jul' }, { val: '08', name: 'Aug' }, { val: '09', name: 'Sep' },
    { val: '10', name: 'Oct' }, { val: '11', name: 'Nov' }, { val: '12', name: 'Dec' }
  ];

  const days = useMemo(() => {
    const yearNum = parseInt(currentYear);
    const monthNum = parseInt(currentMonth);
    const lastDay = new Date(yearNum, monthNum, 0).getDate();
    return Array.from({ length: lastDay }, (_, i) => (i + 1).toString().padStart(2, '0'));
  }, [currentYear, currentMonth]);

  const handleDatePartChange = (part: 'year' | 'month' | 'day', value: string) => {
    let y = currentYear;
    let m = currentMonth;
    let d = currentDay;
    if (part === 'year') y = value;
    if (part === 'month') m = value;
    if (part === 'day') d = value;
    const lastDay = new Date(parseInt(y), parseInt(m), 0).getDate();
    if (parseInt(d) > lastDay) d = lastDay.toString().padStart(2, '0');
    onUpdate({ date: `${y}-${m}-${d}` });
  };

  const calculateDuration = () => {
    if (!startTime || !endTime) return null;
    const [h1, m1] = startTime.split(':').map(Number);
    const [h2, m2] = endTime.split(':').map(Number);
    let startMins = h1 * 60 + m1;
    let endMins = h2 * 60 + m2;

    // Support cross-midnight spanning
    if (endMins <= startMins) {
      endMins += 24 * 60;
    }

    const diff = endMins - startMins;
    const hours = Math.floor(diff / 60);
    const mins = diff % 60;
    return mins > 0 ? `${hours}h ${mins}m` : `${hours} hours`;
  };

  const duration = calculateDuration();
  const selectBaseStyles = "bg-gray-50 border border-gray-100 rounded-2xl px-3 py-3.5 focus:ring-2 focus:ring-accent/20 focus:outline-none transition-all font-medium appearance-none cursor-pointer text-sm w-full";

  return (
    <div className="w-full mb-16">
      <div className="text-center mb-10">
        <h2 className="text-4xl md:text-5xl font-serif font-bold text-primary mb-4">Choose your perfect day</h2>
        <div className="w-20 h-[2px] bg-accent mx-auto"></div>
      </div>

      <div className="bg-white border border-gray-100 shadow-xl rounded-[2.5rem] p-8 md:p-10 space-y-10">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-end">
          <div className="space-y-3">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              Event Date
            </label>
            <div className="flex gap-2">
              <select value={currentDay} onChange={(e) => handleDatePartChange('day', e.target.value)} className={selectBaseStyles}>
                {days.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
              <select value={currentMonth} onChange={(e) => handleDatePartChange('month', e.target.value)} className={selectBaseStyles}>
                {months.map(m => <option key={m.val} value={m.val}>{m.name}</option>)}
              </select>
              <select value={currentYear} onChange={(e) => handleDatePartChange('year', e.target.value)} className={selectBaseStyles}>
                {years.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              Start Time
            </label>
            <select value={startTime} onChange={(e) => onUpdate({ startTime: e.target.value })} className={selectBaseStyles}>
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div className="space-y-3 relative">
            <label className="text-[10px] font-bold uppercase tracking-widest text-accent flex items-center">
              End Time
            </label>
            <select value={endTime} onChange={(e) => onUpdate({ endTime: e.target.value })} className={selectBaseStyles}>
              {times.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
            {duration && (
              <div className="absolute -bottom-6 right-0 text-[9px] font-bold text-accent uppercase tracking-tighter bg-accent/5 px-2 py-0.5 rounded-full">
                Duration: {duration}
              </div>
            )}
          </div>
        </div>

        <div className="pt-8 border-t border-gray-100">
          <p className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-400 mb-6 text-center">Include Services</p>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${photoEnabled ? 'bg-accent/5 border-accent shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className={`text-xs font-bold uppercase tracking-widest ${photoEnabled ? 'text-primary' : 'text-gray-400'}`}>Photography</span>
              </div>
              <input type="checkbox" checked={photoEnabled} onChange={(e) => onTogglePhoto(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>

            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${videoEnabled ? 'bg-accent/5 border-accent shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className={`text-xs font-bold uppercase tracking-widest ${videoEnabled ? 'text-primary' : 'text-gray-400'}`}>Videography</span>
              </div>
              <input type="checkbox" checked={videoEnabled} onChange={(e) => onToggleVideo(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>

            <label className={`flex items-center justify-between p-4 rounded-2xl border transition-all cursor-pointer group ${contentEnabled ? 'bg-accent/5 border-accent/40 shadow-sm' : 'bg-gray-50 border-gray-100 opacity-60'}`}>
              <div className="flex items-center space-x-3">
                <span className={`text-xs font-bold uppercase tracking-widest ${contentEnabled ? 'text-primary' : 'text-gray-400'}`}>Content Creator</span>
              </div>
              <input type="checkbox" checked={contentEnabled} onChange={(e) => onToggleContent(e.target.checked)} className="w-5 h-5 accent-accent rounded cursor-pointer" />
            </label>
          </div>
        </div>
      </div>
    </div>
  );
};

