export default BudgetAllocation;

import React, { useState, useCallback, useMemo } from 'react';
import PriceSlider from './components/PriceSlider';
import BudgetAllocation from './components/BudgetAllocation';
import ChatAssistant from './components/ChatAssistant';
import EventScheduling from './components/EventScheduling';
import { PORTFOLIO_IMAGES, PHOTO_PRICING, VIDEO_PRICING, CONTENT_PRICING, COST_MULTIPLIER } from './constants';
import { Selection, PricingConstants } from './types';

const App: React.FC = () => {
  // Helper to calculate hours from time strings, handling cross-midnight intervals
  const getDurationHours = (start: string, end: string): number => {
    const [h1, m1] = start.split(':').map(Number);
    const [h2, m2] = end.split(':').map(Number);
    let startMins = h1 * 60 + m1;
    let endMins = h2 * 60 + m2;

    // If end time is before or same as start time, assume it's the next day
    if (endMins <= startMins) {
      endMins += 24 * 60;
    }

    return (endMins - startMins) / 60;
  };

  // Scheduling State - Initialized to 12:00 - 14:00 (2 hours)
  const [eventSchedule, setEventSchedule] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '12:00',
    endTime: '14:00',
  });

  const scheduleDuration = useMemo(() => 
    getDurationHours(eventSchedule.startTime, eventSchedule.endTime), 
    [eventSchedule.startTime, eventSchedule.endTime]
  );

  // Photography State - Initialized to 2h * $25 = $50
  const [photoBudget, setPhotoBudget] = useState(50);
  const [photoSelection, setPhotoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Videography State - Initialized to 2h * $25 = $50
  const [videoBudget, setVideoBudget] = useState(50);
  const [videoSelection, setVideoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Content Creator State - Initialized to 2h * $25 = $50
  const [contentBudget, setContentBudget] = useState(50);
  const [contentSelection, setContentSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: false,
    sessionsEnabled: false,
    hoursEnabled: true,
    droneEnabled: false,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  const getHourPrice = useCallback((isSecond: boolean, pricing: PricingConstants) => 
    isSecond ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE, []);

  const calculateTotal = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    const baseTotal = (
      (sel.hoursEnabled ? sel.hours * hourPrice : 0) +
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0)
    );
    return Math.round(baseTotal * COST_MULTIPLIER);
  }, [getHourPrice]);

  const calculateMinBudget = useCallback((sel: Selection, pricing: PricingConstants) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);
    const fixedCosts = 
      (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0) +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0);
    const effectiveHours = Math.max(2, sel.hours);
    return Math.round((fixedCosts + (effectiveHours * hourPrice)) * COST_MULTIPLIER);
  }, [getHourPrice]);

  // Unified update functions that can optionally force-sync the budget
  const updatePhoto = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setPhotoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, PHOTO_PRICING);
      const newMin = calculateMinBudget(next, PHOTO_PRICING);
      setPhotoBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  const updateVideo = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setVideoSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, VIDEO_PRICING);
      const newMin = calculateMinBudget(next, VIDEO_PRICING);
      setVideoBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  const updateContent = useCallback((update: Partial<Selection>, syncBudget: boolean = false) => {
    setContentSelection(prev => {
      const next = { ...prev, ...update };
      const newTotal = calculateTotal(next, CONTENT_PRICING);
      const newMin = calculateMinBudget(next, CONTENT_PRICING);
      setContentBudget(prevB => syncBudget ? newTotal : Math.max(newMin, newTotal, prevB));
      return next;
    });
  }, [calculateTotal, calculateMinBudget]);

  // Handle schedule changes and sync hours + budget
  const handleScheduleUpdate = (data: { date?: string; startTime?: string; endTime?: string }) => {
    const nextSchedule = { ...eventSchedule, ...data };
    setEventSchedule(nextSchedule);

    const newDuration = getDurationHours(nextSchedule.startTime, nextSchedule.endTime);
    const syncedHours = Math.max(2, newDuration);

    // Update hours and reset budget to exactly match the new total cost
    updatePhoto({ hours: syncedHours }, true);
    updateVideo({ hours: syncedHours }, true);
    updateContent({ hours: syncedHours }, true);
  };

  const currentPhotoTotal = useMemo(() => calculateTotal(photoSelection, PHOTO_PRICING), [photoSelection, calculateTotal]);
  const currentVideoTotal = useMemo(() => calculateTotal(videoSelection, VIDEO_PRICING), [videoSelection, calculateTotal]);
  const currentContentTotal = useMemo(() => calculateTotal(contentSelection, CONTENT_PRICING), [contentSelection, calculateTotal]);

  const allSummary = useMemo(() => {
    const photo: string[] = [];
    const video: string[] = [];
    const content: string[] = [];

    if (photoSelection.serviceEnabled) {
      if (photoSelection.hours > 0) {
        const specialistCount = photoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Photographer' : 'Photographers';
        photo.push(`${specialistCount} ${label} for ${photoSelection.hours} Hours`);
      }
      if (photoSelection.sessions > 0) photo.push(`${photoSelection.sessions} Photo-Session(s)`);
      if (photoSelection.books > 0) photo.push(`${photoSelection.books} Photo-Book(s)`);
      if (photoSelection.droneSessions > 0) photo.push(`${photoSelection.droneSessions} Drone Photo Session(s)`);
    }

    if (videoSelection.serviceEnabled) {
      if (videoSelection.hours > 0) {
        const specialistCount = videoSelection.secondSpecialist ? 2 : 1;
        const label = specialistCount === 1 ? 'Videographer' : 'Videographers';
        video.push(`${specialistCount} ${label} for ${videoSelection.hours} Hours`);
      }
      if (videoSelection.sessions > 0) video.push(`${videoSelection.sessions} Love-Story(ies)`);
      if (videoSelection.books > 0) video.push(`${videoSelection.books} Crane Location(s)`);
      if (videoSelection.droneSessions > 0) video.push(`${videoSelection.droneSessions} Drone Video Session(s)`);
    }

    if (contentSelection.serviceEnabled) {
      if (contentSelection.hours > 0) {
        content.push(`${contentSelection.hours} Hours of Content Creation`);
      }
    }

    return { photo, video, content };
  }, [photoSelection, videoSelection, contentSelection]);

  const handlePhotoSliderChange = (newVal: number) => {
    if (!photoSelection.serviceEnabled) return;
    const min = calculateMinBudget(photoSelection, PHOTO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setPhotoBudget(effectiveVal);

    setPhotoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * PHOTO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * PHOTO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * PHOTO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = (effectiveVal / COST_MULTIPLIER) - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, PHOTO_PRICING);
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleVideoSliderChange = (newVal: number) => {
    if (!videoSelection.serviceEnabled) return;
    const min = calculateMinBudget(videoSelection, VIDEO_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setVideoBudget(effectiveVal);

    setVideoSelection(prev => {
      const fixedCosts = 
        (prev.sessionsEnabled ? prev.sessions * VIDEO_PRICING.SESSION_PRICE : 0) +
        (prev.booksEnabled ? prev.books * VIDEO_PRICING.BOOK_PRICE : 0) +
        (prev.droneEnabled ? prev.droneSessions * VIDEO_PRICING.DRONE_PRICE : 0);
      const remainingBudget = (effectiveVal / COST_MULTIPLIER) - fixedCosts;
      const hourPrice = getHourPrice(prev.secondSpecialist, VIDEO_PRICING);
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const handleContentSliderChange = (newVal: number) => {
    if (!contentSelection.serviceEnabled) return;
    const min = calculateMinBudget(contentSelection, CONTENT_PRICING);
    const effectiveVal = Math.max(min, newVal);
    setContentBudget(effectiveVal);

    setContentSelection(prev => {
      const remainingBudget = (effectiveVal / COST_MULTIPLIER);
      const hourPrice = CONTENT_PRICING.HOUR_PRICE;
      const newHours = Math.max(scheduleDuration, 2, Math.floor(remainingBudget / hourPrice));
      return { ...prev, hours: newHours, hoursEnabled: true };
    });
  };

  const grandTotal = currentPhotoTotal + currentVideoTotal + currentContentTotal;

  return (
    <div className="min-h-screen flex flex-col font-sans text-primary">
      <nav className="fixed top-0 w-full z-50 glass-morphism border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <span className="text-white font-serif font-bold italic">L</span>
            </div>
            <span className="font-serif text-xl font-bold tracking-tight">LUMINA FRAMES</span>
          </div>
          <div className="hidden md:flex space-x-8 text-sm font-medium text-gray-600">
            <a href="#" className="hover:text-accent transition-colors">Portfolio</a>
            <a href="#planner" className="hover:text-accent transition-colors">Pricing</a>
            <a href="#" className="hover:text-accent transition-colors">Our Studio</a>
            <button className="bg-primary text-white px-6 py-2 rounded-full text-xs uppercase tracking-widest hover:bg-accent transition-all">Book Now</button>
          </div>
        </div>
      </nav>

      <header className="pt-32 pb-20 px-6 bg-[#fafafa]">
        <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-12 items-center">
          <div className="space-y-8">
            <h1 className="text-6xl md:text-7xl font-serif font-bold leading-tight">
              Capturing <br />
              <span className="text-accent italic">Timeless</span> <br />
              Moments.
            </h1>
            <p className="text-lg text-gray-500 max-w-md leading-relaxed">
              Professional media services tailored to your budget. From photography to cinematic videography, we frame your story with elegance.
            </p>
            <div className="flex space-x-4">
              <a href="#planner" className="bg-primary text-white px-8 py-4 rounded-full font-medium hover:bg-gray-800 transition-all shadow-lg">Plan Your Session</a>
              <a href="#portfolio" className="border border-gray-300 px-8 py-4 rounded-full font-medium hover:bg-gray-50 transition-all">View Work</a>
            </div>
          </div>
          <div className="relative">
            <div className="aspect-[4/5] rounded-3xl overflow-hidden shadow-2xl">
              <img 
                src="https://images.unsplash.com/photo-1554080353-a576cf803bda?auto=format&fit=crop&q=80&w=1200" 
                alt="Professional camera" 
                className="w-full h-full object-cover"
              />
            </div>
          </div>
        </div>
      </header>

      <section id="planner" className="py-24 px-6 bg-white">
        <div className="max-w-7xl mx-auto space-y-32">

          <EventScheduling 
            date={eventSchedule.date}
            startTime={eventSchedule.startTime}
            endTime={eventSchedule.endTime}
            photoEnabled={photoSelection.serviceEnabled}
            videoEnabled={videoSelection.serviceEnabled}
            contentEnabled={contentSelection.serviceEnabled}
            onUpdate={handleScheduleUpdate}
            onTogglePhoto={(val) => updatePhoto({ serviceEnabled: val }, true)}
            onToggleVideo={(val) => updateVideo({ serviceEnabled: val }, true)}
            onToggleContent={(val) => updateContent({ serviceEnabled: val }, true)}
          />

          <div className={`transition-all duration-500 ${!photoSelection.serviceEnabled ? 'hidden' : ''}`}>
            <div className="bg-gray-50/50 p-8 md:p-12 rounded-[2rem] border border-gray-100 max-w-5xl mx-auto">
              <div className="mb-12 text-center">
                <div className="flex flex-col items-center mb-8">
