                    (photoSelection.serviceEnabled && videoSelection.serviceEnabled ? ' + ' : '') + 
                    (videoSelection.serviceEnabled ? 'Videography' : '') +
                    ((photoSelection.serviceEnabled || videoSelection.serviceEnabled) && contentSelection.serviceEnabled ? ' + ' : '') +
