              <div className={`py-6 px-8 md:py-10 md:px-12 rounded-[3rem] border transition-all shadow-xl overflow-hidden relative group bg-accent/15 border-accent/30`}>
                <div className="absolute top-0 right-0 w-64 h-64 bg-accent/10 blur-[120px] rounded-full -mr-20 -mt-20"></div>
                <div className="relative z-10">
                  {(allSummary.photo.length > 0 || allSummary.video.length > 0 || allSummary.content.length > 0) && (
                    <div className="mb-8">
                      <p className="text-xs uppercase tracking-[0.2em] text-primary font-black mb-6 border-b border-primary/10 pb-4">Selected Package Summary</p>

                      <div className="grid md:grid-cols-3 gap-10 mb-10">
                        {allSummary.photo.length > 0 && (
                          <div className="space-y-4">
                            <p className="text-[15px] uppercase tracking-widest text-black font-black">Photo services</p>
                            <ul className="space-y-3">
                              {allSummary.photo.map((opt, idx) => (
