                            Book Your Experience
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-accent/5 py-6 px-8 rounded-[2rem] border border-accent/10">
                <h3 className="text-xl font-serif font-bold mb-2">Photo/Video Consultation</h3>
                <ChatAssistant budget={grandTotal} />
