        </div>
      </section>

      {/* STICKY FOOTER */}
      <footer className="fixed bottom-0 left-0 w-full z-40 glass-morphism border-t border-gray-200 shadow-[0_-10px_25px_-5px_rgba(0,0,0,0.1)] py-4 px-6 md:px-12">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex flex-col md:flex-row md:items-center gap-2 md:gap-8">
