            <div className="hidden lg:flex items-center space-x-4 border-l border-gray-200 pl-8">
              <div className="flex flex-col">
                <span className="text-[9px] uppercase tracking-widest text-gray-400 font-bold">Includes</span>
                <span className="text-xs font-medium text-gray-600">
                  { (photoSelection.serviceEnabled ? 'Photography' : '') + 
                    (photoSelection.serviceEnabled && videoSelection.serviceEnabled ? ' + ' : '') + 
                    (videoSelection.serviceEnabled ? 'Videography' : '') +
                    ((photoSelection.serviceEnabled || videoSelection.serviceEnabled) && contentSelection.serviceEnabled ? ' + ' : '') +
                    (contentSelection.serviceEnabled ? 'Content Creation' : '') || 'No services selected'
