      {/* STICKY FOOTER */}
      <footer className="fixed bottom-0 left-0 w-full z-40 glass-morphism border-t border-gray-200 shadow-[0_-10px_25px_-5px_rgba(0,0,0,0.1)] py-4 px-6 md:px-12">
        <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-4">
              <p className="text-xs md:text-sm uppercase tracking-[0.3em] text-gray-500 font-bold whitespace-nowrap">Total Investment</p>
              <p className="text-3xl md:text-5xl font-serif font-bold text-primary leading-none tracking-tighter">
                ${grandTotal}
              </p>
