        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-gray-100 p-3 rounded-2xl animate-pulse text-gray-400 text-xs">Thinking...</div>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 flex space-x-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
