import React from 'react';
import { Selection, PricingConstants } from '../types';
import { COST_MULTIPLIER } from '../constants';

interface BudgetAllocationProps {
  selection: Selection;
  onUpdate: (update: Partial<Selection>) => void;
  maxBudget: number;
  pricing: PricingConstants;
  type: 'photo' | 'video' | 'content';
  showSpecialist?: boolean;
  allowedItems?: ('hours' | 'sessions' | 'books' | 'droneSessions')[];
}

const BudgetAllocation: React.FC<BudgetAllocationProps> = ({ 
  selection, 
  onUpdate, 
  maxBudget, 
  pricing, 
  type,
  showSpecialist = true,
  allowedItems = ['hours', 'sessions', 'books', 'droneSessions']
}) => {
  const currentHourPrice = selection.secondSpecialist ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE;

  const isFreeSessionEligible = type === 'photo' && selection.hours >= 10 && selection.sessions > 0;
  const effectiveSessions = isFreeSessionEligible ? Math.max(0, selection.sessions - 1) : (selection.sessionsEnabled ? selection.sessions : 0);

  const baseTotalCost = 
    (selection.hoursEnabled ? selection.hours * currentHourPrice : 0) +
    (effectiveSessions * pricing.SESSION_PRICE) +
    (selection.booksEnabled ? selection.books * pricing.BOOK_PRICE : 0) +
    (selection.droneEnabled ? selection.droneSessions * pricing.DRONE_PRICE : 0);

  const actualTotalCost = Math.round(baseTotalCost * COST_MULTIPLIER);

  const labels = {
    hours: type === 'photo' ? 'Photography Hours' : type === 'video' ? 'Videography Hours' : 'Content Creation Hours',
    sessions: type === 'photo' ? 'Photo-Sessions' : 'Love-Story',
    books: type === 'photo' ? 'Photo-Books' : 'Crane',
    drone: type === 'photo' ? 'Drone Photography' : 'Drone Videography',
    specialist: type === 'photo' ? 'Second Photographer' : 'Second Videographer',
    totalCost: type === 'photo' ? 'Total estimated cost for Photography' : type === 'video' ? 'Total estimated cost for Videography' : 'Total estimated cost for Content Creation'
  };

  const allItems = [
    { 
      id: 'hours' as const,
      name: labels.hours, 
      count: selection.hours, 
      enabled: selection.hoursEnabled,
      price: currentHourPrice, 
      unitLabel: 'per hour',
      min: 2
    },
    { 
      id: 'sessions' as const,
      name: labels.sessions, 
      count: selection.sessions, 
      enabled: selection.sessionsEnabled,
      price: pricing.SESSION_PRICE, 
      unitLabel: type === 'photo' ? 'per session' : 'per Love-Story',
      min: 0,
      isFree: isFreeSessionEligible
    },
    { 
      id: 'books' as const,
      name: labels.books, 
      count: selection.books, 
      enabled: selection.booksEnabled,
      price: pricing.BOOK_PRICE, 
      unitLabel: type === 'photo' ? 'per photo-book 30x20cm' : 'per location',
      min: 0
    },
    { 
      id: 'droneSessions' as const,
      name: labels.drone, 
      count: selection.droneSessions, 
      enabled: selection.droneEnabled,
      price: pricing.DRONE_PRICE, 
      unitLabel: 'per session',
      min: 0
    },
  ];

  const items = allItems.filter(item => allowedItems.includes(item.id));

  const handleAdjust = (id: string, delta: number) => {
    if (!selection.serviceEnabled) return;
    const currentVal = selection[id as keyof Selection] as number;
    const itemConfig = items.find(item => item.id === id);
    const minVal = itemConfig?.min ?? 0;

    const newVal = Math.max(minVal, currentVal + delta);
    const update: any = { [id]: newVal };

    if (id === 'hours') update.hoursEnabled = true;
    if (id === 'sessions') update.sessionsEnabled = true;
    if (id === 'books') update.booksEnabled = true;
    if (id === 'droneSessions') update.droneEnabled = true;

    onUpdate(update);
  };

  return (
    <div className="space-y-6 mt-10">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {items.map((item) => (
          <div 
            key={item.id} 
            className={`relative group overflow-hidden bg-white py-4 px-6 rounded-2xl shadow-sm border transition-all hover:shadow-md ${
              item.enabled ? 'border-accent ring-1 ring-accent/20' : 'border-gray-100 opacity-60'
            }`}
          >
            <div className="flex justify-between items-start mb-1 gap-2">
              <div className="flex flex-col">
                <h4 className="text-[15.4px] font-bold text-gray-800 leading-tight pt-1">{item.name}</h4>
                {item.id === 'sessions' && type === 'photo' && item.isFree && (
                  <span className="text-[9px] font-black text-accent uppercase tracking-tighter bg-accent/10 px-1.5 py-0.5 rounded inline-block w-fit mt-1">
                    1 FREE SESSION
                  </span>
                )}
              </div>
              <div className="text-lg font-bold text-accent bg-accent/5 px-2 py-1 rounded-lg whitespace-nowrap">
                {Math.round((item.id === 'sessions' && item.isFree ? Math.max(0, item.count - 1) : item.count) * item.price * COST_MULTIPLIER)} €
              </div>
            </div>

            <div className="text-[11px] text-gray-500 mb-3 leading-relaxed">
              <span className="whitespace-nowrap">{item.price} € {item.unitLabel}</span>
              {item.id === 'sessions' && type === 'photo' && (
                <span className="text-[11px] text-accent font-bold block mt-1">
                   (get 1 free if 10+ Photography Hours)
                </span>
              )}
            </div>

            <div className="flex items-center justify-between bg-gray-50 rounded-xl p-1.5">
              <button 
                onClick={() => handleAdjust(item.id, -1)}
                className="w-9 h-9 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-[26.4px] font-bold"
                aria-label="Decrease"
              >
                -
              </button>
              <span className="text-[26.4px] font-serif font-bold text-primary px-3">
                {item.count}
              </span>
              <button 
                onClick={() => handleAdjust(item.id, 1)}
                className="w-9 h-9 flex items-center justify-center rounded-lg bg-white border border-gray-200 text-gray-500 hover:bg-gray-100 transition-colors text-[26.4px] font-bold"
                aria-label="Increase"
              >
                +
              </button>
            </div>

            {item.id === 'hours' && showSpecialist && (
              <div className="mt-3 space-y-1">
                <label className="flex items-center space-x-2 cursor-pointer group/check">
                  <input 
                    type="checkbox"
                    checked={selection.secondSpecialist}
                    onChange={(e) => onUpdate({ secondSpecialist: e.target.checked })}
                    className="w-4 h-4 accent-accent rounded"
                  />
                  <span className="text-11px] font-bold uppercase tracking-wider text-gray-600 group-hover/check:text-accent transition-colors">
                    {labels.specialist}
                  </span>
                </label>
              </div>
            )}
          </div>
        ))}
      </div>

      <div className="py-6 px-8 rounded-[2rem] border transition-all bg-accent/5 border-accent/20 shadow-sm">
        <div className="flex justify-between items-center">
          <div>
            <p className="text-xs uppercase tracking-widest text-gray-500 font-bold mb-1">{labels.totalCost}</p>
            <p className="text-4xl font-serif font-bold text-primary whitespace-nowrap">
              {selection.serviceEnabled ? actualTotalCost : 0} €
            </p>
          </div>
          {type === 'photo' && selection.hours < 10 && (
            <div className="text-right hidden sm:block">
              <p className="text-[10px] text-gray-400 font-medium uppercase tracking-widest">PROMO ALERT</p>
              <p className="text-[11px] text-gray-500 italic">Select 10+ hours to get 1 free session!</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BudgetAllocation;

import React, { useState, useCallback, useMemo } from 'react';
import BudgetAllocation from './components/BudgetAllocation';
import ChatAssistant from './components/ChatAssistant';
import EventScheduling from './components/EventScheduling';
import { PORTFOLIO_IMAGES, PHOTO_PRICING, VIDEO_PRICING, CONTENT_PRICING, COST_MULTIPLIER } from './constants';
import { Selection, PricingConstants } from './types';

const App: React.FC = () => {
  // Booking Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [bookingForm, setBookingForm] = useState({
    name: '',
    email: '',
    town: '',
    phone: '',
    additionalNote: ''
  });

  // Helper to format date as "1st of April 2026"
  const formatDateNarrative = (dateStr: string): string => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const day = date.getDate();
    const month = date.toLocaleString('en-US', { month: 'long' });
    const year = date.getFullYear();

    const getOrdinal = (n: number) => {
      const s = ["th", "st", "nd", "rd"];
      const v = n % 100;
      return n + (s[(v - 20) % 10] || s[v] || s[0]);
    };

    return `${getOrdinal(day)} of ${month} ${year}`;
  };

  // Helper to calculate hours from time strings
  const getDurationHours = (start: string, end: string): number => {
    const [h1, m1] = start.split(':').map(Number);
    const [h2, m2] = end.split(':').map(Number);
    let startMins = h1 * 60 + m1;
    let endMins = h2 * 60 + m2;

    if (endMins <= startMins) {
      endMins += 24 * 60;
    }

    return (endMins - startMins) / 60;
  };

  // Scheduling State
  const [eventSchedule, setEventSchedule] = useState({
    date: new Date().toISOString().split('T')[0],
    startTime: '12:00',
    endTime: '14:00',
  });

  // Photography State
  const [photoSelection, setPhotoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Videography State
  const [videoSelection, setVideoSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: true,
    sessionsEnabled: true,
    hoursEnabled: true,
    droneEnabled: true,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  // Content Creator State
  const [contentSelection, setContentSelection] = useState<Selection>({
    hours: 2,
    sessions: 0,
    books: 0,
    droneSessions: 0,
    booksEnabled: false,
    sessionsEnabled: false,
    hoursEnabled: true,
    droneEnabled: false,
    secondSpecialist: false,
    serviceEnabled: true,
  });

  const getHourPrice = useCallback((isSecond: boolean, pricing: PricingConstants) => 
    isSecond ? pricing.HOUR_PRICE * 2 : pricing.HOUR_PRICE, []);

  const calculateTotal = useCallback((sel: Selection, pricing: PricingConstants, isPhoto: boolean = false) => {
    if (!sel.serviceEnabled) return 0;
    const hourPrice = getHourPrice(sel.secondSpecialist, pricing);

    let sessionCost = (sel.sessionsEnabled ? sel.sessions * pricing.SESSION_PRICE : 0);
    if (isPhoto && sel.hours >= 10 && sel.sessions > 0) {
      sessionCost = Math.max(0, sel.sessions - 1) * pricing.SESSION_PRICE;
    }

    const baseTotal = (
      (sel.hoursEnabled ? sel.hours * hourPrice : 0) +
      sessionCost +
      (sel.booksEnabled ? sel.books * pricing.BOOK_PRICE : 0) +
      (sel.droneEnabled ? sel.droneSessions * pricing.DRONE_PRICE : 0)
    );
    return Math.round(baseTotal * COST_MULTIPLIER);
  }, [getHourPrice]);

  const updatePhoto = useCallback((update: Partial<Selection>) => {
    setPhotoSelection(prev => ({ ...prev, ...update }));
  }, []);

  const updateVideo = useCallback((update: Partial<Selection>) => {
    setVideoSelection(prev => ({ ...prev, ...update }));
  }, []);

  const updateContent = useCallback((update: Partial<Selection>) => {
    setContentSelection(prev => ({ ...prev, ...update }));
  }, []);

  const handleScheduleUpdate = (data: { date?: string; startTime?: string; endTime?: string }) => {
    const nextSchedule = { ...eventSchedule, ...data };
    setEventSchedule(nextSchedule);

    const newDuration = getDurationHours(nextSchedule.startTime, nextSchedule.endTime);
    const syncedHours = Math.max(2, newDuration);

    updatePhoto({ hours: syncedHours });
    updateVideo({ hours: syncedHours });
    updateContent({ hours: syncedHours });
  };

  const currentPhotoTotal = useMemo(() => calculateTotal(photoSelection, PHOTO_PRICING, true), [photoSelection, calculateTotal]);
  const currentVideoTotal = useMemo(() => calculateTotal(videoSelection, VIDEO_PRICING), [videoSelection, calculateTotal]);
  const currentContentTotal = useMemo(() => calculateTotal(contentSelection, CONTENT_PRICING), [contentSelection, calculateTotal]);

  const grandTotal = currentPhotoTotal + currentVideoTotal + currentContentTotal;

  // Generate the narrative summary as paragraphs
  const narrativeParagraphs = useMemo(() => {
    const formattedDate = formatDateNarrative(eventSchedule.date);
    const name = bookingForm.name || "[Name]";
    const town = bookingForm.town || "[Town]";
    const email = bookingForm.email || "[Email]";
    const phone = bookingForm.phone || "[Phone]";

    const durationHours = getDurationHours(eventSchedule.startTime, eventSchedule.endTime);
    const durationText = durationHours === 1 ? "1 hour" : `${durationHours} hours`;

    const paragraphs: string[] = [];

    // Paragraph 1: User Info and Schedule
    paragraphs.push(`My name is ${name} and I am planning an event in ${town} on the ${formattedDate}. I am interested in booking your services from ${eventSchedule.startTime} until ${eventSchedule.endTime} (${durationText}). You can reach me at ${email} or by phone at ${phone}.`);

    // Photo Paragraph
    if (photoSelection.serviceEnabled) {
      const spec = photoSelection.secondSpecialist ? "two photographers" : "a professional photographer";
      let pStr = `For the photography, I would like to have ${spec} present for ${photoSelection.hours} hours. `;
      if (photoSelection.sessions > 0) {
        pStr += `I'm also planning for ${photoSelection.sessions} photo session(s)${photoSelection.hours >= 10 ? ', and I would like to include the complimentary session in this total' : ''}. `;
      }
      if (photoSelection.books > 0) pStr += `I'd also like to order ${photoSelection.books} of your high-quality photo books. `;
      if (photoSelection.droneSessions > 0) pStr += `Finally, please include ${photoSelection.droneSessions} drone photography session(s) in the package. `;
      paragraphs.push(pStr.trim());
    }

    // Video Paragraph
    if (videoSelection.serviceEnabled) {
      const spec = videoSelection.secondSpecialist ? "two videographers" : "a professional videographer";
      let vStr = `Regarding videography, I am looking to book ${spec} for ${videoSelection.hours} hours. `;
      if (videoSelection.sessions > 0) vStr += `I'm interested in capturing ${videoSelection.sessions} Love-Story session(s). `;
      if (videoSelection.books > 0) vStr += `Please include ${videoSelection.books} Crane filming locations as part of the coverage. `;
      if (videoSelection.droneSessions > 0) vStr += `I'd also like to have ${videoSelection.droneSessions} drone video session(s) included. `;
      paragraphs.push(vStr.trim());
    }

    // Content Creator Paragraph
    if (contentSelection.serviceEnabled) {
      paragraphs.push(`I would also like to have a dedicated Content Creator on-site for ${contentSelection.hours} hours to capture social-ready moments.`);
    }

    // Total Paragraph
    paragraphs.push(`The total estimated investment for this personalized package comes to ${grandTotal} € plus travel expenses.`);

    return paragraphs;
  }, [bookingForm, eventSchedule, photoSelection, videoSelection, contentSelection, grandTotal]);

  const handleSendBooking = () => {
    const narrativeText = narrativeParagraphs.join('\n\n');
    const noteBlock = bookingForm.additionalNote ? `Additional Note:\n"${bookingForm.additionalNote}"\n\n` : '';

    const body = `Hello Lumina Frames Team,\n\nI would like to inquire about a booking with the following details:\n\n${narrativeText}\n\n${noteBlock}I look forward to hearing from you soon!\n\nBest regards,\n${bookingForm.name || 'Client'}`;

    const mailtoUrl = `mailto:3latko@gmail.com?subject=Booking Request - Lumina Frames&body=${encodeURIComponent(body)}`;
    window.location.href = mailtoUrl;
    setIsModalOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-primary relative">
      <nav className="fixed top-0 w-full z-50 glass-morphism border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
