            onUpdate={handleScheduleUpdate} onTogglePhoto={(v) => updatePhoto({ serviceEnabled: v })} onToggleVideo={(v) => updateVideo({ serviceEnabled: v })} onToggleContent={(v) => updateContent({ serviceEnabled: v })}
