          <div className="flex items-center gap-4">
            <p className="text-xs uppercase tracking-[0.3em] text-gray-500 font-bold">{t.footer.investment}</p>
            <p className="text-4xl font-serif font-bold text-primary whitespace-nowrap">{grandTotal} €</p>
          </div>
          <div className="flex items-center text-accent"><div className="w-2 h-2 rounded-full bg-accent animate-pulse mr-2"></div><span className="text-[10px] uppercase tracking-widest font-bold">{t.footer.liveEstimate}</span></div>
        </div>
      </footer>

      {/* Actual Site Footer */}
      <footer className="bg-primary text-white py-20 px-6 pb-32">
        <div className="max-w-7xl mx-auto grid md:grid-cols-4 gap-12">
          <div className="col-span-2 space-y-6">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-accent rounded-lg flex items-center justify-center">
                <span className="text-primary font-serif font-bold italic">D</span>
              </div>
