                  <div className="w-24 h-[1px] bg-accent/30 mx-auto mt-4"></div>
                </div>
                <BudgetAllocation lang={lang} selection={srv.selection} onUpdate={srv.update} maxBudget={0} pricing={srv.pricing} type={srv.type} showSpecialist={srv.specialist} allowedItems={srv.items} />
              </div>
            </div>
          ))}

          <div className="grid lg:grid-cols-3 gap-12 items-start">
            <div className="lg:col-span-2 space-y-8">
              <div className="py-10 px-12 rounded-[3rem] border transition-all shadow-xl relative bg-accent/15 border-accent/30">
