                   <div className="pt-8 border-t border-primary/10 flex flex-col md:flex-row justify-between items-center gap-6">
                     <div className="flex-1 w-full">
                       <PriceSlider value={grandTotal} onChange={() => {}} title={t.footer.investment} />
                     </div>
                     <button onClick={() => setIsModalOpen(true)} className="bg-primary text-white px-10 py-5 rounded-full font-bold uppercase tracking-widest text-xs hover:scale-105 transition-transform shadow-lg whitespace-nowrap">
                       {t.summary.bookExperience}
                     </button>
