            { selection: videoSelection, update: updateVideo, pricing: VIDEO_PRICING, type: 'video' as const, label: t.services.videography, specialist: true },
            { selection: contentSelection, update: updateContent, pricing: CONTENT_PRICING, type: 'content' as const, label: t.services.contentCreator, specialist: false, items: ['hours'] as any }
