          <div className="flex items-center text-accent flex-shrink-0"><div className="w-2 h-2 rounded-full bg-accent animate-pulse mr-2"></div><span className="text-[9px] md:text-[10px] uppercase tracking-widest font-bold">{t.footer.liveEstimate}</span></div>
        </div>
      </footer>

      {/* Actual Site Footer */}
      <footer className="bg-primary text-white py-20 px-6 pb-32">
        <div className="max-w-7xl mx-auto grid md:grid-cols-4 gap-12">
          <div className="col-span-2 space-y-6">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-accent rounded-lg flex items-center justify-center">
                <span className="text-primary font-serif font-bold italic">D</span>
              </div>
              <span className="font-serif text-2xl font-bold tracking-tight">DRIM TEAMS</span>
            </div>
            <p className="text-gray-400 max-w-sm leading-relaxed text-sm">
              {t.footer.mission}
            </p>
          </div>
          <div className="space-y-4">
            <h4 className="text-accent font-serif font-bold">{t.footer.contact}</h4>
            <p className="text-gray-400 text-sm">3latko@gmail.com</p>
            <p className="text-gray-400 text-sm">+1 (555) 000-DRIM</p>
            <p className="text-gray-400 text-sm italic">Struga, Macedonia</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

